        let active = true;
        async function load() {
            const [employeeRows, employerSettings] = await Promise.all([getEmployees(), getSettings()]);
            if (!active) return;
            setEmployees(employeeRows);
            setSettings(employerSettings);

            // Attempt to restore session data
            let restoredData = null;
            let restoredStep = 0;
            try {
                const stored = sessionStorage.getItem("lekkerledger-contract-draft-state");
                if (stored) {
                    const parsed = JSON.parse(stored);
                    restoredData = parsed.formData;
                    restoredStep = parsed.currentStep;
                }
            } catch (e) {
                // Ignore parse errors
            }

            if (restoredData) {
                setFormData(restoredData);
                setCurrentStep(restoredStep);
            } else {
                const selectedEmployee = employeeRows.find((employee) => employee.id === employeeIdParam) || employeeRows[0];
                if (selectedEmployee) {
                    setFormData((current) => ({
                        ...current,
                        employeeId: selectedEmployee.id,
                        jobTitle: current.jobTitle || selectedEmployee.role || "Domestic worker",
                        placeOfWork: current.placeOfWork || employerSettings.employerAddress || "",
                        salary: {
                            ...current.salary!,
                            amount: current.salary?.amount || Number((selectedEmployee.hourlyRate * 195).toFixed(2)),
                        },
                    }));
                }
            }
            setLoading(false);
        }
        load();
        return () => {
            active = false;
        };
    }, [employeeIdParam]);

    const selectedEmployee = employees.find((employee) => employee.id === formData.employeeId);

    const handleNext = () => setCurrentStep((step) => Math.min(step + 1, WIZARD_STEPS.length - 1));
    const handleBack = () => setCurrentStep((step) => Math.max(step - 1, 0));

    const handleSave = async () => {
        if (!selectedEmployee || !settings) return;
        setSaving(true);
        try {
            const contract: Contract = {
                id: crypto.randomUUID(),
                householdId: selectedEmployee.householdId ?? "default",
                employeeId: selectedEmployee.id,
                status: "draft",
                version: formData.version ?? 1,
                effectiveDate: formData.effectiveDate!,
                jobTitle: formData.jobTitle!,
                placeOfWork: formData.placeOfWork || settings.employerAddress || "",
                duties: formData.duties || ["General cleaning"],
                workingHours: formData.workingHours!,
                salary: formData.salary!,
                leave: formData.leave!,
                terms: formData.terms!,
                createdAt: new Date().toISOString(),
                updatedAt: new Date().toISOString(),
            };
            await saveContract(contract);
            sessionStorage.removeItem("lekkerledger-contract-draft-state"); // Clear state on success
            router.push("/documents?tab=contracts");
        } catch (error) {
            console.error(error);
            setSaving(false);
        }
    };

    if (loading) return null;

    if (settings && !canUseContractGenerator(getUserPlan(settings))) {
        return (
            <div className="max-w-4xl mx-auto space-y-8 pb-20">
                <PageHeader
                    title="Employment contract"
                    subtitle="Work through the actual job terms first, then save a draft PDF to review before anyone signs."
                />
                <FeatureGateCard
                    title="Contract drafts are available on Standard and Pro"
                    description="Free keeps payroll and payslips simple. Upgrade if you need employment contracts, document storage, and fuller household records."
                />
            </div>
        );
    }

    return (
        <div className="max-w-4xl mx-auto space-y-8 pb-20">
            <div className="flex items-center justify-between">
                <button
                    onClick={() => currentStep === 0 ? router.back() : handleBack()}
                    className="flex items-center gap-2 text-sm font-bold text-[var(--text-muted)] hover:text-[var(--text)] transition-colors"
                >
                    <ArrowLeft className="h-4 w-4" /> {currentStep === 0 ? "Back" : "Previous step"}
                </button>
            </div>

            <div className="space-y-3">
                <PageHeader
                    title="Employment contract"
                    subtitle="Work through the actual job terms first, then generate a draft PDF to review before anyone signs."
                />
                <Stepper steps={WIZARD_STEPS} currentStep={currentStep} className="py-4" />
            </div>

            <Card className="glass-panel border-none p-5">
                <div className="space-y-2 text-sm text-[var(--text-muted)]">
                    <p className="text-[10px] font-black uppercase tracking-[0.16em] text-[var(--text-muted)]">Template details</p>
                    <p>
                        Template version: <strong className="text-[var(--text)]">{CONTRACT_TEMPLATE_META.versionLabel}</strong> ┬╖ Last updated: <strong className="text-[var(--text)]">{CONTRACT_TEMPLATE_META.updatedAtLabel}</strong>
                    </p>
                    <p>
                        Source: <a href={CONTRACT_TEMPLATE_META.sourceHref} target="_blank" rel="noopener noreferrer" className="font-semibold text-[var(--primary)] hover:underline">{CONTRACT_TEMPLATE_META.sourceLabel}</a> ┬╖ <strong className="text-[var(--text)]">{CONTRACT_TEMPLATE_META.reviewLabel}</strong>
                    </p>
                </div>
            </Card>

            <ContractFormWizard
                currentStep={currentStep}
                setCurrentStep={setCurrentStep}
                formData={formData}
                setFormData={setFormData}
                employees={employees}
                settings={settings}
                saving={saving}
                onSave={handleSave}
                onBackToTop={() => router.back()}
            />
        </div>
    );
}

"use client";

import * as React from "react";
import Link from "next/link";
import { useRouter, useSearchParams } from "next/navigation";
import {
    Cloud,
    Download,
    Eye,
    FileSpreadsheet,
    FileText,
    FolderOpen,
    HardDrive,
    History,
    Lock,
    ScrollText,
    Trash2,
    Upload,
} from "lucide-react";
import { format } from "date-fns";
import { Button } from "@/components/ui/button";
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import { Card, CardContent } from "@/components/ui/card";
import { PageHeader } from "@/components/ui/page-header";
import { FeatureGateCard } from "@/components/ui/feature-gate-card";
import { EmptyState } from "@/components/ui/empty-state";
import { DataTable } from "@/components/ui/data-table";
import { FiltersBar, type FilterChip } from "@/components/ui/filters-bar";
import { DocumentPreview } from "@/components/ui/document-preview";
import { ContractRow } from "@/components/documents/ContractRow";
import { ContractsTab } from "@/components/documents/ContractsTab";
import { useToast } from "@/components/ui/toast";
import { PLANS, type PlanConfig } from "@/config/plans";
import {
    filterRecordsForArchiveWindow,
    getArchiveUpgradeHref,
    getUpgradePlanForArchive,
    isUploadedDocument,
} from "@/lib/archive";
import {
    canUseContractSignedCopyUpload,
    canUseDocumentsHub,
    canUseVaultUploads,
    canUseYearEndSummary,
    getUserPlan,
} from "@/lib/entitlements";
import { deleteDriveFile, uploadVaultFileToDrive } from "@/lib/google-drive";
import { getStoredGoogleAccessToken } from "@/lib/google-session";
import { generateEmploymentContract, buildContractFileName } from "@/lib/contracts/pdfGenerator";
import { generatePayslipPdfBytes } from "@/lib/pdf";
import {
    deleteDocumentMeta,
    getAllLeaveRecords,
    getAllPayslips,
    getContracts,
    getDocumentFile,
    getDocuments,
    getEmployees,
    getPayPeriods,
    getPayslipsForEmployee,
    getSettings,
    saveDocumentFile,
    saveDocumentMeta,
    subscribeToDataChanges,
    updateContractStatus,
} from "@/lib/storage";
import { generateYearEndSummaryPdf, getYearEndSummaryStatus } from "@/lib/year-end-summary";
import type { Contract, DocumentMeta, Employee, LeaveRecord, PayPeriod, PayslipInput } from "@/lib/schema";

const TABS = ["Payslips", "Contracts", "Exports", "Vault"] as const;
type Tab = typeof TABS[number];
type VaultCategory = "contracts" | "employee-docs" | "compliance" | "other";

const TAB_TYPE_MAP: Record<Exclude<Tab, "Contracts">, DocumentMeta["type"]> = {
    Payslips: "payslip",
    Exports: "export",
    Vault: "archive",
};

const VAULT_CATEGORIES: Array<{ value: VaultCategory; label: string }> = [
    { value: "contracts", label: "Contracts" },
    { value: "employee-docs", label: "Employee docs" },
    { value: "compliance", label: "Compliance" },
    { value: "other", label: "Other" },
];

const VAULT_MAX_FILE_BYTES = 10 * 1024 * 1024;
const ACCEPTED_UPLOAD_EXTENSIONS = [".pdf", ".jpg", ".jpeg", ".png", ".docx"];

function matchesAllowedUpload(file: File): boolean {
    const lowerName = file.name.toLowerCase();
    return ACCEPTED_UPLOAD_EXTENSIONS.some((extension) => lowerName.endsWith(extension));
}

function isPreviewableMimeType(mimeType: string | undefined): boolean {
    if (!mimeType) return false;
    return mimeType === "application/pdf" || mimeType.startsWith("image/");
}

function downloadBlob(blob: Blob, fileName: string) {
    const url = URL.createObjectURL(blob);
    const anchor = document.createElement("a");
    anchor.href = url;
    anchor.download = fileName;
    document.body.appendChild(anchor);
    anchor.click();
    document.body.removeChild(anchor);
    window.setTimeout(() => URL.revokeObjectURL(url), 1000);
}


function buildYearEndSummaryFileName(year: number, householdName?: string) {
    const safeName = (householdName?.trim() || "Employment_Summary").replace(/\s+/g, "_");
    return `${safeName}_${year}.pdf`;
}

function ArchiveBanner({ hiddenCount, href, label }: { hiddenCount: number; href: string; label: string }) {
    if (hiddenCount <= 0) return null;
    return (
        <div className="rounded-2xl border border-[var(--primary)]/20 bg-[var(--primary)]/8 px-4 py-4">
            <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
                <div>
                    <p className="text-sm font-bold text-[var(--text)]">
                        You have {hiddenCount} older record{hiddenCount === 1 ? "" : "s"}.
                    </p>
                    <p className="text-sm text-[var(--text-muted)]">Upgrade to browse your full history in the app.</p>
                </div>
                <Link href={href}>
                    <Button className="bg-[var(--primary)] text-white hover:bg-[var(--primary-hover)]">{label}</Button>
                </Link>
            </div>
        </div>
    );
}

export default function DocumentsPage() {
    const { toast } = useToast();
    const router = useRouter();
    const searchParams = useSearchParams();
    const initialTab = (searchParams.get("tab") || "").toLowerCase();
    const defaultTab = initialTab === "contracts"
        ? "Contracts"
        : initialTab === "vault"
            ? "Vault"
            : initialTab === "exports"
                ? "Exports"
                : "Payslips";

    const [activeTab, setActiveTab] = React.useState<Tab>(defaultTab as Tab);
    const [loading, setLoading] = React.useState(true);
    const [documents, setDocuments] = React.useState<DocumentMeta[]>([]);
    const [contracts, setContracts] = React.useState<Contract[]>([]);
    const [employees, setEmployees] = React.useState<Employee[]>([]);
    const [allPayslips, setAllPayslips] = React.useState<PayslipInput[]>([]);
    const [allLeaveRecords, setAllLeaveRecordsState] = React.useState<LeaveRecord[]>([]);
    const [payPeriods, setPayPeriods] = React.useState<PayPeriod[]>([]);
    const [plan, setPlan] = React.useState<PlanConfig>(PLANS.free);
    const [settings, setSettings] = React.useState<Awaited<ReturnType<typeof getSettings>> | null>(null);
    const [search, setSearch] = React.useState("");
    const [empFilter, setEmpFilter] = React.useState<string>("");
    const [contractStateFilter, setContractStateFilter] = React.useState<Contract["status"] | "needs_action" | "All">("All");
    const [vaultCategoryFilter, setVaultCategoryFilter] = React.useState<string>("");
    const [nextVaultCategory, setNextVaultCategory] = React.useState<VaultCategory>("other");
    const [summaryYear, setSummaryYear] = React.useState<number | "">("");
    const [previewDoc, setPreviewDoc] = React.useState<DocumentMeta | null>(null);
    const [previewFileName, setPreviewFileName] = React.useState<string | undefined>(undefined);
    const [previewUrl, setPreviewUrl] = React.useState<string | null>(null);
    const [isGeneratingPreview, setIsGeneratingPreview] = React.useState(false);
    const [isGeneratingSummary, setIsGeneratingSummary] = React.useState(false);
    const [deletingDocumentId, setDeletingDocumentId] = React.useState<string | null>(null);
    const uploadInputRef = React.useRef<HTMLInputElement | null>(null);
    const pdfCache = React.useRef<Record<string, string>>({});
    const [uploadTargetContract, setUploadTargetContract] = React.useState<Contract | null>(null);

    React.useEffect(() => {
        setActiveTab(defaultTab as Tab);
    }, [defaultTab]);

    React.useEffect(() => {
        let active = true;

        async function load() {
            if (!active) return;
            setLoading(true);
            try {
                const [
                    docs,
                    contractRows,
                    employeeRows,
                    userSettings,
                    payslipRows,
                    leaveRows,
                    payPeriodRows,
                ] = await Promise.all([
                    getDocuments(),
                    getContracts(),
                    getEmployees(),
                    getSettings(),
                    getAllPayslips(),
                    getAllLeaveRecords(),
                    getPayPeriods(),
                ]);

                if (!active) return;
                setDocuments(docs);
                setContracts(contractRows);
                setEmployees(employeeRows);
                setSettings(userSettings);
                setPlan(getUserPlan(userSettings));
                setAllPayslips(payslipRows);
                setAllLeaveRecordsState(leaveRows);
                setPayPeriods(payPeriodRows);
            } catch (error) {
                console.error("Failed to load documents hub", error);
            } finally {
                if (active) {
                    setLoading(false);
                }
            }
        }

        void load();
        const unsubscribe = subscribeToDataChanges(load);
        return () => {
            active = false;
            unsubscribe();
        };
    }, []);

    const employeeNameById = React.useMemo(
        () => Object.fromEntries(employees.map((employee) => [employee.id, employee.name])),
        [employees],
    );

    const employeeFilters: FilterChip[] = employees.map((employee) => ({
        key: employee.id,
        label: employee.name,
        active: empFilter === employee.id,
    }));

    const archiveUpgradePlanId = getUpgradePlanForArchive(plan.id);
    const archiveUpgradeHref = getArchiveUpgradeHref(plan.id);
    const archiveUpgradeLabel = archiveUpgradePlanId ? `Upgrade to ${PLANS[archiveUpgradePlanId].label}` : "Upgrade";
    const vaultUpgradeHref = "/upgrade?plan=pro";
    const vaultUploadsAllowed = canUseVaultUploads(plan);
    const contractSignedCopyUploadAllowed = canUseContractSignedCopyUpload(plan);
    const yearEndSummaryAllowed = canUseYearEndSummary(plan);

    const payslipDocuments = React.useMemo(
        () => documents.filter((document) => document.type === TAB_TYPE_MAP.Payslips),
        [documents],
    );
    const exportDocuments = React.useMemo(
        () => documents.filter((document) => document.type === TAB_TYPE_MAP.Exports),
        [documents],
    );
    const vaultDocuments = React.useMemo(
        () => documents.filter((document) => document.type === TAB_TYPE_MAP.Vault && document.source === "uploaded"),
        [documents],
    );

    const payslipArchiveResult = React.useMemo(
        () => filterRecordsForArchiveWindow(
            payslipDocuments.filter((document) => !empFilter || document.employeeId === empFilter),
            plan,
            (document) => document.createdAt,
            { alwaysVisible: isUploadedDocument },
        ),
        [empFilter, payslipDocuments, plan],
    );

    const exportArchiveResult = React.useMemo(
        () => filterRecordsForArchiveWindow(
            exportDocuments.filter((document) => !empFilter || document.employeeId === empFilter),
            plan,
            (document) => document.createdAt,
            { alwaysVisible: isUploadedDocument },
        ),
        [empFilter, exportDocuments, plan],
    );

    const contractsArchiveResult = React.useMemo(
        () => filterRecordsForArchiveWindow(
            contracts.filter((contract) => !empFilter || contract.employeeId === empFilter),
            plan,
            (contract) => contract.updatedAt || contract.createdAt,
        ),
        [contracts, empFilter, plan],
    );

    const filteredPayslipDocuments = React.useMemo(() => {
        const query = search.trim().toLowerCase();
        return payslipArchiveResult.visible.filter((document) => {
            if (!query) return true;
            const employeeName = (document.employeeId ? employeeNameById[document.employeeId] : "")?.toLowerCase() ?? "";
            return document.fileName.toLowerCase().includes(query) || employeeName.includes(query);
        });
    }, [employeeNameById, payslipArchiveResult.visible, search]);

    const filteredExportDocuments = React.useMemo(() => {
        const query = search.trim().toLowerCase();
        return exportArchiveResult.visible.filter((document) => {
            if (!query) return true;
            const employeeName = (document.employeeId ? employeeNameById[document.employeeId] : "")?.toLowerCase() ?? "";
            return document.fileName.toLowerCase().includes(query) || employeeName.includes(query);
        });
    }, [employeeNameById, exportArchiveResult.visible, search]);

    const filteredContracts = React.useMemo(() => {
        const query = search.trim().toLowerCase();
        return contractsArchiveResult.visible.filter((contract) => {
            if (contractStateFilter !== "All") {
                if (contractStateFilter === "needs_action") {
                    if (contract.status !== "draft" && contract.status !== "awaiting_signed_copy") return false;
                } else if (contract.status !== contractStateFilter) {
                    return false;
                }
            }
            if (!query) return true;
            const employeeName = employeeNameById[contract.employeeId]?.toLowerCase() ?? "";
            return contract.jobTitle.toLowerCase().includes(query) || employeeName.includes(query);
        });
    }, [contractsArchiveResult.visible, employeeNameById, search, contractStateFilter]);

    const filteredVaultDocuments = React.useMemo(() => {
        const query = search.trim().toLowerCase();
        return vaultDocuments.filter((document) => {
            if (empFilter && document.employeeId !== empFilter) return false;
            if (vaultCategoryFilter && document.vaultCategory !== vaultCategoryFilter) return false;
            if (!query) return true;
            const employeeName = (document.employeeId ? employeeNameById[document.employeeId] : "")?.toLowerCase() ?? "";
            return document.fileName.toLowerCase().includes(query) || employeeName.includes(query);
        });
    }, [empFilter, employeeNameById, search, vaultCategoryFilter, vaultDocuments]);

    const availableSummaryYears = React.useMemo(
        () => getYearEndSummaryStatus(payPeriods, new Date().getFullYear()).availableYears,
        [payPeriods],
    );

    React.useEffect(() => {
        if (!summaryYear && availableSummaryYears.length > 0) {
            setSummaryYear(availableSummaryYears[0]);
        }
    }, [availableSummaryYears, summaryYear]);

    const selectedYearStatus = React.useMemo(
        () => summaryYear ? getYearEndSummaryStatus(payPeriods, Number(summaryYear)) : null,
        [payPeriods, summaryYear],
    );

    const handlePreview = async (doc: DocumentMeta) => {
        setPreviewDoc(doc);
        setPreviewFileName(doc.fileName);

        if (pdfCache.current[doc.id]) {
            setPreviewUrl(pdfCache.current[doc.id]);
            return;
        }

        setIsGeneratingPreview(true);

        try {
            if (doc.type === "payslip" && doc.employeeId) {
                const [payslips, latestSettings] = await Promise.all([getPayslipsForEmployee(doc.employeeId), getSettings()]);
                const employee = employees.find((entry) => entry.id === doc.employeeId);
                const payslip = payslips.find((entry) => entry.id === doc.id);
                if (!payslip || !employee || !latestSettings) {
                    throw new Error("Could not find that payslip.");
                }
                const pdfBytes = await generatePayslipPdfBytes(employee, payslip, latestSettings);
                const blob = new Blob([new Uint8Array(pdfBytes)], { type: "application/pdf" });
                const url = URL.createObjectURL(blob);
                pdfCache.current[doc.id] = url;
                setPreviewUrl(url);
                return;
            }

            const accessToken = getStoredGoogleAccessToken();
            const blob = await getDocumentFile(doc.id, { accessToken });
            if (!blob) {
                throw new Error("That file is not available yet.");
            }

            const mimeType = blob.type || doc.mimeType || "application/octet-stream";
            if (isPreviewableMimeType(mimeType)) {
                const url = URL.createObjectURL(blob);
                pdfCache.current[doc.id] = url;
                setPreviewUrl(url);
                return;
            }

            setPreviewDoc(null);
            setPreviewFileName(undefined);
            downloadBlob(blob, doc.fileName);
        } catch (error) {
            toast(error instanceof Error ? error.message : "Could not open that document.", "error");
            setPreviewDoc(null);
            setPreviewFileName(undefined);
        } finally {
            setIsGeneratingPreview(false);
        }
    };

    const openContractPreview = (contract: Contract) => {
        router.push(`/contracts/${contract.id}/preview`);
    };

    const downloadContract = async (contract: Contract) => {
        if (!settings) return;
        const employee = employees.find((entry) => entry.id === contract.employeeId);
        if (!employee) return;
        const pdfBytes = await generateEmploymentContract(contract, employee, settings);
        const blob = new Blob([new Uint8Array(pdfBytes)], { type: "application/pdf" });
        downloadBlob(blob, buildContractFileName(contract, employee));

        if (contract.status === "draft") {
            await updateContractStatus(contract.id, "awaiting_signed_copy");
        }
    };

    const handleMarkFinal = async (contract: Contract) => {
        try {
            await updateContractStatus(contract.id, "final", { finalizedAt: new Date().toISOString() });
            toast("Contract marked as final.", "success");
        } catch (error) {
            toast("Could not update contract status.", "error");
        }
    };

    const handleContractUploadClick = (contract: Contract) => {
        if (!contractSignedCopyUploadAllowed) return;
        setUploadTargetContract(contract);
        uploadInputRef.current?.click();
    };

    const handleVaultUploadClick = () => {
        if (!vaultUploadsAllowed) {
            router.push(vaultUpgradeHref);
            return;
        }
        setUploadTargetContract(null);
        uploadInputRef.current?.click();
    };

    const handleSignedDocumentSelected = async (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        const targetContract = uploadTargetContract;
        event.target.value = "";

        if (!file) return;

        if (targetContract && file.type !== "application/pdf") {
            toast("Signed contracts must be uploaded as PDF files.", "error");
            return;
        } else if (!targetContract && !matchesAllowedUpload(file)) {
            toast("Upload a PDF, JPG, PNG, or DOCX file.", "error");
            return;
        }

        if (file.size > VAULT_MAX_FILE_BYTES) {
            toast("Files must be 10 MB or smaller.", "error");
            return;
        }

        try {
            const id = crypto.randomUUID();
            const createdAt = new Date().toISOString();

            if (targetContract) {
                if (!contractSignedCopyUploadAllowed) {
                    router.push("/upgrade?plan=standard");
                    return;
                }

                const employee = employees.find((entry) => entry.id === targetContract.employeeId);
                const nextDocument: DocumentMeta = {
                    id,
                    householdId: employee?.householdId ?? settings?.activeHouseholdId ?? "default",
                    type: "archive",
                    employeeId: employee?.id,
                    periodId: targetContract.id,
                    fileName: file.name,
                    mimeType: file.type || "application/octet-stream",
                    source: "uploaded",
                    vaultCategory: "contracts",
                    sizeBytes: file.size,
                    createdAt,
                };

                await saveDocumentFile(id, file);
                await saveDocumentMeta(nextDocument);
                await updateContractStatus(targetContract.id, "signed_copy_stored", { signedDocumentId: id });
                setDocuments((current) => [nextDocument, ...current]);
                toast("Signed copy saved to Documents.", "success");
                return;
            }

            if (!vaultUploadsAllowed) {
                router.push(vaultUpgradeHref);
                return;
            }

            const accessToken = getStoredGoogleAccessToken();
            if (!accessToken) {
                toast("Reconnect Google in Settings before uploading to the Vault.", "error");
                return;
            }

            const driveFileId = await uploadVaultFileToDrive(accessToken, file, {
                documentId: id,
                fileName: file.name,
                mimeType: file.type || "application/octet-stream",
            });

            const nextDocument: DocumentMeta = {
                id,
                householdId: settings?.activeHouseholdId ?? "default",
                type: "archive",
                fileName: file.name,
                mimeType: file.type || "application/octet-stream",
                source: "uploaded",
                vaultCategory: nextVaultCategory,
                sizeBytes: file.size,
                createdAt,
                driveFileId,
            };

            await saveDocumentFile(id, file);
            await saveDocumentMeta(nextDocument);
            setDocuments((current) => [nextDocument, ...current]);
            toast("Document uploaded to Vault.", "success");
        } catch (error) {
            toast(error instanceof Error ? error.message : "Could not save that file.", "error");
        } finally {
            setUploadTargetContract(null);
        }
    };

    const handleDeleteVaultDocument = async (document: DocumentMeta) => {
        if (!vaultUploadsAllowed) return;
        if (typeof window !== "undefined" && !window.confirm(`Delete ${document.fileName}?`)) {
            return;
        }

        try {
            setDeletingDocumentId(document.id);
            if (document.driveFileId) {
                const accessToken = getStoredGoogleAccessToken();
                if (!accessToken) {
                    throw new Error("Reconnect Google before deleting Vault files.");
                }
                await deleteDriveFile(accessToken, document.driveFileId);
            }
            await deleteDocumentMeta(document.id);
            setDocuments((current) => current.filter((entry) => entry.id !== document.id));
            if (previewDoc?.id === document.id) {
                if (previewUrl) URL.revokeObjectURL(previewUrl);
                setPreviewDoc(null);
                setPreviewFileName(undefined);
                setPreviewUrl(null);
            }
            toast("Document removed from Vault.", "success");
        } catch (error) {
            toast(error instanceof Error ? error.message : "Could not delete that file.", "error");
        } finally {
            setDeletingDocumentId(null);
        }
    };

    const handleGenerateYearEndSummary = async () => {
        if (!summaryYear || !yearEndSummaryAllowed || !settings) return;

        try {
            setIsGeneratingSummary(true);
            const pdfBytes = await generateYearEndSummaryPdf({
                year: Number(summaryYear),
                householdName: settings.employerName || "Employment Summary",
                employees,
                payslips: allPayslips,
                leaveRecords: allLeaveRecords,
                payPeriods,
            });

            const id = crypto.randomUUID();
            const createdAt = new Date().toISOString();
            const fileName = buildYearEndSummaryFileName(Number(summaryYear), settings.employerName || "Employment Summary");
            const blob = new Blob([new Uint8Array(pdfBytes).buffer], { type: "application/pdf" });
            const nextDocument: DocumentMeta = {
                id,
                householdId: settings.activeHouseholdId ?? "default",
                type: "export",
                fileName,
                mimeType: "application/pdf",
                source: "generated",
                createdAt,
                sizeBytes: blob.size,
            };

            await saveDocumentFile(id, blob);
            await saveDocumentMeta(nextDocument);
            setDocuments((current) => [nextDocument, ...current]);
            toast("Year-end summary saved to Exports.", "success");
        } catch (error) {
            toast(error instanceof Error ? error.message : "Could not generate the year-end summary.", "error");
        } finally {
            setIsGeneratingSummary(false);
        }
    };

    const closePreview = React.useCallback(() => {
        if (previewUrl) URL.revokeObjectURL(previewUrl);
        setPreviewDoc(null);
        setPreviewFileName(undefined);
        setPreviewUrl(null);
    }, [previewUrl]);

    const hasAnyContent = documents.length > 0 || contracts.length > 0;

    if (loading) {
        return (
            <>
                <PageHeader title="Documents" subtitle="Payslips, contracts, exports, and vault history" />
                <EmptyState
                    title="Loading documents"
                    description="Pulling together your payslips, contracts, exports, and stored records."
                    icon={FolderOpen}
                />
            </>
        );
    }

    if (!canUseDocumentsHub(plan)) {
        return (
            <>
                <PageHeader title="Documents" subtitle="Payslips, contracts, exports, and vault history" />
                <FeatureGateCard
                    title="Documents hub is available on Standard and Pro"
                    description="Free keeps payroll and payslips simple for one worker. Upgrade for contracts, document uploads, exports, and longer record access."
                />
            </>
        );
    }

    return (
        <>
            <PageHeader
                title="Documents"
                subtitle="Payslips, contracts, exports, and vault history in one place"
                actions={activeTab === "Vault" ? (
                    vaultUploadsAllowed ? (
                        <Button
                            type="button"
                            className="gap-2 bg-[var(--primary)] text-white hover:bg-[var(--primary-hover)] font-bold"
                            onClick={handleVaultUploadClick}
                        >
                            <Upload className="h-4 w-4" /> Upload Document
                        </Button>
                    ) : (
                        <Link href={vaultUpgradeHref}>
                            <Button variant="outline" className="gap-2 font-bold">
                                <Lock className="h-4 w-4" /> Upgrade to Pro
                            </Button>
                        </Link>
                    )
                ) : undefined}
            />

            <input
                ref={uploadInputRef}
                type="file"
                accept=".pdf,.jpg,.jpeg,.png,.docx"
                className="hidden"
                onChange={handleSignedDocumentSelected}
            />

            <div className="ultrawide-grid">
                <div className="ultrawide-main space-y-6">
                    <div className="flex items-center gap-1 border-b border-[var(--border)] -mx-4 overflow-x-auto px-4 no-scrollbar lg:mx-0 lg:px-0">
                        {TABS.map((tab) => (
                            <button
                                key={tab}
                                type="button"
                                onClick={() => setActiveTab(tab)}
                                className={`whitespace-nowrap border-b-2 px-4 py-3 text-sm font-bold transition-colors ${activeTab === tab ? "border-[var(--primary)] text-[var(--primary)]" : "border-transparent text-[var(--text-muted)] hover:text-[var(--text)]"}`}
                            >
                                {tab}
                            </button>
                        ))}
                    </div>

                    {activeTab === "Contracts" && filteredContracts.length > 0 && (
                        <div className="inline-flex rounded-full border border-orange-200 bg-orange-50 px-3 py-1.5 text-xs text-orange-800">
                            <strong>Review before signing:</strong>&nbsp;Templates are starting points. Verify with a labour lawyer if unsure.
                        </div>
                    )}

                    {hasAnyContent && (
                        <FiltersBar
                            searchPlaceholder={`Search ${activeTab.toLowerCase()}...`}
                            searchValue={search}
                            onSearchChange={setSearch}
                            filters={employeeFilters}
                            onFilterToggle={(key) => setEmpFilter((current) => current === key ? "" : key)}
                        />
                    )}

                    {activeTab === "Contracts" && filteredContracts.length > 0 && (
                        <div className="inline-flex rounded-full border border-orange-200 bg-orange-50 px-3 py-1.5 text-xs text-orange-800 mb-4">
                            <strong>Review before signing:</strong>&nbsp;Templates are starting points. Verify with a labour lawyer if unsure.
                        </div>
                    )}

                    {activeTab === "Vault" && (
                        <Card className="glass-panel border-none">
                            <CardContent className="space-y-4 p-5">
                                <div className="flex flex-col gap-3 lg:flex-row lg:items-center lg:justify-between">
                                    <div>
                                        <p className="text-[10px] font-black uppercase tracking-[0.16em] text-[var(--text-muted)]">Vault categories</p>
                                        <p className="mt-1 text-sm text-[var(--text-muted)]">Store signed contracts, ID copies, and other supporting records in one place.</p>
                                    </div>
                                    {vaultUploadsAllowed && (
                                        <label className="flex items-center gap-2 text-sm font-semibold text-[var(--text)]">
                                            New uploads:
                                            <select
                                                value={nextVaultCategory}
                                                onChange={(event) => setNextVaultCategory(event.target.value as VaultCategory)}
                                                className="rounded-xl border border-[var(--border)] bg-[var(--surface-1)] px-3 py-2 text-sm text-[var(--text)]"
                                            >
                                                {VAULT_CATEGORIES.map((category) => (
                                                    <option key={category.value} value={category.value}>
                                                        {category.label}
                                                    </option>
                                                ))}
                                            </select>
                                        </label>
                                    )}
                                </div>

                                <div className="flex flex-wrap gap-2">
                                    <button
                                        type="button"
                                        onClick={() => setVaultCategoryFilter("")}
                                        className={`rounded-full border px-3 py-1.5 text-[11px] font-bold uppercase tracking-wide ${vaultCategoryFilter === "" ? "border-[var(--primary)] bg-[var(--primary)] text-white" : "border-[var(--border)] text-[var(--text-muted)]"}`}
                                    >
                                        All files
                                    </button>
                                    {VAULT_CATEGORIES.map((category) => (
                                        <button
                                            key={category.value}
                                            type="button"
                                            onClick={() => setVaultCategoryFilter((current) => current === category.value ? "" : category.value)}
                                            className={`rounded-full border px-3 py-1.5 text-[11px] font-bold uppercase tracking-wide ${vaultCategoryFilter === category.value ? "border-[var(--primary)] bg-[var(--primary)] text-white" : "border-[var(--border)] text-[var(--text-muted)]"}`}
                                        >
                                            {category.label}
                                        </button>
                                    ))}
                                </div>

                                {!vaultUploadsAllowed && (
                                    <div className="rounded-2xl border border-[var(--primary)]/20 bg-[var(--primary)]/8 px-4 py-4">
                                        <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
                                            <div>
                                                <p className="text-sm font-bold text-[var(--text)]">Upload anything to the Vault on Pro</p>
                                                <p className="text-sm text-[var(--text-muted)]">Standard keeps signed contract copies active on contract pages. Pro unlocks general document uploads here.</p>
                                            </div>
                                            <Link href={vaultUpgradeHref}>
                                                <Button className="bg-[var(--primary)] text-white hover:bg-[var(--primary-hover)]">Upgrade to Pro</Button>
                                            </Link>
                                        </div>
                                    </div>
                                )}

                                {(vaultUploadsAllowed || vaultDocuments.some((document) => document.driveFileId)) && (
                                    <p className="text-xs text-[var(--text-muted)]">Your files are stored in your Google account.</p>
                                )}
                            </CardContent>
                        </Card>
                    )}

                    {activeTab === "Exports" && plan.id !== "free" && (
                        <Card className="glass-panel border-none">
                            <CardContent className="space-y-4 p-5">
                                <div>
                                    <p className="text-[10px] font-black uppercase tracking-[0.16em] text-[var(--text-muted)]">Year-end summary</p>
                                    <h2 className="mt-1 text-lg font-black text-[var(--text)]">One PDF for the full year</h2>
                                    <p className="mt-1 text-sm text-[var(--text-muted)]">Summarise finalised payroll totals and leave taken for each worker over one calendar year.</p>
                                </div>

                                {yearEndSummaryAllowed ? (
                                    <>
                                        {availableSummaryYears.length === 0 ? (
                                            <p className="text-sm text-[var(--text-muted)]">Finalise a payroll month first, then you can generate a year-end summary here.</p>
                                        ) : (
                                            <>
                                                <div className="flex flex-col gap-3 sm:flex-row sm:items-center">
                                                    <label className="flex items-center gap-2 text-sm font-semibold text-[var(--text)]">
                                                        Year
                                                        <select
                                                            value={summaryYear}
                                                            onChange={(event) => setSummaryYear(Number(event.target.value))}
                                                            className="rounded-xl border border-[var(--border)] bg-[var(--surface-1)] px-3 py-2 text-sm text-[var(--text)]"
                                                        >
                                                            {availableSummaryYears.map((year) => (
                                                                <option key={year} value={year}>
                                                                    {year}
                                                                </option>
                                                            ))}
                                                        </select>
                                                    </label>
                                                    <Button
                                                        type="button"
                                                        onClick={handleGenerateYearEndSummary}
                                                        disabled={isGeneratingSummary || !summaryYear}
                                                        className="bg-[var(--primary)] text-white hover:bg-[var(--primary-hover)]"
                                                    >
                                                        {isGeneratingSummary ? "Generating..." : "Generate PDF"}
                                                    </Button>
                                                </div>
                                                {selectedYearStatus && selectedYearStatus.unlockedMonthCount > 0 && (
                                                    <div className="rounded-2xl border border-[var(--primary)]/20 bg-[var(--primary)]/8 px-4 py-3 text-sm text-[var(--text)]">
                                                        {selectedYearStatus.unlockedMonthCount} month{selectedYearStatus.unlockedMonthCount === 1 ? "" : "s"} in {summaryYear} have not been finalised yet. The summary will only include finalised months.
                                                    </div>
                                                )}
                                            </>
                                        )}
                                    </>
                                ) : (
                                    <div className="rounded-2xl border border-[var(--primary)]/20 bg-[var(--primary)]/8 px-4 py-4">
                                        <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
                                            <div>
                                                <p className="text-sm font-bold text-[var(--text)]">Year-end summaries are available on Pro</p>
                                                <p className="text-sm text-[var(--text-muted)]">Keep one ready-to-share PDF for your records or your tax practitioner.</p>
                                            </div>
                                            <Link href={vaultUpgradeHref}>
                                                <Button className="bg-[var(--primary)] text-white hover:bg-[var(--primary-hover)]">Upgrade to Pro</Button>
                                            </Link>
                                        </div>
                                    </div>
                                )}
                            </CardContent>
                        </Card>
                    )}

                    {activeTab === "Contracts" ? (
                        <ContractsTab
                            contracts={filteredContracts}
                            employees={employees}
                            documents={documents}
                            hiddenCount={contractsArchiveResult.hiddenCount}
                            archiveUpgradeHref={archiveUpgradeHref}
                            archiveUpgradeLabel={archiveUpgradeLabel}
                            contractStateFilter={contractStateFilter}
                            setContractStateFilter={setContractStateFilter}
                            openContractPreview={openContractPreview}
                            downloadContract={downloadContract}
                            handleContractUploadClick={handleContractUploadClick}
                            handlePreview={handlePreview}
                            handleMarkFinal={handleMarkFinal}
                            toast={toast}
                        />
                    ) : activeTab === "Payslips" ? (
                        filteredPayslipDocuments.length === 0 ? (
                            <EmptyState
                                title="No payslips yet"
                                description="Payslip PDFs will appear here automatically after you finalise your first pay period."
                                icon={FileText}
                                actionLabel={employees.length === 0 ? "Add your first employee" : "Run payroll"}
                                actionHref={employees.length === 0 ? "/employees/new" : "/payroll"}
                            />
                        ) : (
                            <>
                                <DataTable<DocumentMeta>
                                    data={filteredPayslipDocuments}
                                    keyField={(doc) => doc.id}
                                    emptyMessage="No payslips match your filters."
                                    columns={[
                                        {
                                            key: "fileName",
                                            label: "File",
                                            render: (doc) => (
                                                <div className="flex items-center gap-3">
                                                    <div className="flex h-9 w-9 shrink-0 items-center justify-center rounded-lg bg-[var(--surface-2)]">
                                                        <FileText className="h-4 w-4 text-[var(--primary)]" />
                                                    </div>
                                                    <span className="type-body-bold text-[var(--text)]">{doc.fileName}</span>
                                                </div>
                                            ),
                                        },
                                        {
                                            key: "employee",
                                            label: "Employee",
                                            render: (doc) => <span className="type-body text-[var(--text-muted)]">{doc.employeeId ? employeeNameById[doc.employeeId] ?? "Unknown" : "-"}</span>,
                                        },
                                        {
                                            key: "storage",
                                            label: "Storage",
                                            render: (doc) => (
                                                <div className="flex w-fit items-center gap-1.5 rounded-full border border-[var(--border)] bg-[var(--surface-2)] px-2 py-1">
                                                    {doc.driveFileId ? <Cloud className="h-3 w-3 text-[var(--primary)]" /> : <HardDrive className="h-3 w-3 text-[var(--text-muted)]" />}
                                                    <span className="text-[10px] font-black uppercase text-[var(--text-muted)]">{doc.driveFileId ? "Drive backup" : "This device"}</span>
                                                </div>
                                            ),
                                        },
                                        {
                                            key: "date",
                                            label: "Added",
                                            render: (doc) => <span className="type-body text-[var(--text-muted)]">{format(new Date(doc.createdAt), "d MMM yyyy")}</span>,
                                        },
                                        {
                                            key: "actions",
                                            label: "",
                                            align: "right",
                                            render: (doc) => (
                                                <Button variant="ghost" size="sm" className="h-9 w-9 p-0" onClick={() => void handlePreview(doc)}>
                                                    <Eye className="h-4 w-4 text-[var(--primary)]" />
                                                </Button>
                                            ),
                                        },
                                    ]}
                                />
                                <ArchiveBanner hiddenCount={payslipArchiveResult.hiddenCount} href={archiveUpgradeHref} label={archiveUpgradeLabel} />
                            </>
                        )
                    ) : activeTab === "Exports" ? (
                        filteredExportDocuments.length === 0 ? (
                            <EmptyState
                                title="No exports available"
                                description="Official documents like Year-End Summaries and UIF declarations will be generated here. Finalise a payroll month to unlock your first export."
                                icon={FileSpreadsheet}
                            />
                        ) : (
                            <>
                                <DataTable<DocumentMeta>
                                    data={filteredExportDocuments}
                                    keyField={(doc) => doc.id}
                                    emptyMessage="No exports match your filters."
                                    columns={[
                                        {
                                            key: "fileName",
                                            label: "File",
                                            render: (doc) => (
                                                <div className="flex items-center gap-3">
                                                    <div className="flex h-9 w-9 shrink-0 items-center justify-center rounded-lg bg-[var(--surface-2)]">
                                                        <FileSpreadsheet className="h-4 w-4 text-[var(--primary)]" />
                                                    </div>
                                                    <span className="type-body-bold text-[var(--text)]">{doc.fileName}</span>
                                                </div>
                                            ),
                                        },
                                        {
                                            key: "storage",
                                            label: "Storage",
                                            render: (doc) => (
                                                <div className="flex w-fit items-center gap-1.5 rounded-full border border-[var(--border)] bg-[var(--surface-2)] px-2 py-1">
                                                    {doc.driveFileId ? <Cloud className="h-3 w-3 text-[var(--primary)]" /> : <HardDrive className="h-3 w-3 text-[var(--text-muted)]" />}
                                                    <span className="text-[10px] font-black uppercase text-[var(--text-muted)]">{doc.driveFileId ? "Drive backup" : "This device"}</span>
                                                </div>
                                            ),
                                        },
                                        {
                                            key: "date",
                                            label: "Added",
                                            render: (doc) => <span className="type-body text-[var(--text-muted)]">{format(new Date(doc.createdAt), "d MMM yyyy")}</span>,
                                        },
                                        {
                                            key: "actions",
                                            label: "",
                                            align: "right",
                                            render: (doc) => (
                                                <Button variant="ghost" size="sm" className="h-9 w-9 p-0" onClick={() => void handlePreview(doc)}>
                                                    <Eye className="h-4 w-4 text-[var(--primary)]" />
                                                </Button>
                                            ),
                                        },
                                    ]}
                                />
                                <ArchiveBanner hiddenCount={exportArchiveResult.hiddenCount} href={archiveUpgradeHref} label={archiveUpgradeLabel} />
                            </>
                        )
                    ) : filteredVaultDocuments.length === 0 ? (
                        vaultUploadsAllowed ? (
                            <div className="rounded-2xl border border-dashed border-[var(--border)] bg-[var(--surface-1)] p-10 text-center">
                                <FolderOpen className="mx-auto mb-3 h-10 w-10 text-[var(--text-muted)]" strokeWidth={1.5} />
                                <p className="text-sm font-bold text-[var(--text)]">Secure Document Vault</p>
                                <p className="mt-1 text-sm text-[var(--text-muted)]">A safe place to upload and store external employee records. Keep ID copies, sick notes, and compliance forms organised here.</p>
                                <Button className="mt-4 bg-[var(--primary)] text-white hover:bg-[var(--primary-hover)]" onClick={handleVaultUploadClick}>
                                    Upload document
                                </Button>
                            </div>
                        ) : (
                            <FeatureGateCard
                                title="Secure Document Vault"
                                description="Vault uploads are available on Pro. A safe place to upload and store external employee records. Keep ID copies, sick notes, and compliance forms organised here."
                                ctaLabel="Upgrade to Pro"
                                href={vaultUpgradeHref}
                                eyebrow="Pro"
                                benefits={[
                                    "Private document vault in your Google account",
                                    "All uploaded files stay in one place",
                                    "Upload general household employment paperwork",
                                ]}
                            />
                        )
                    ) : (
                        <DataTable<DocumentMeta>
                            data={filteredVaultDocuments}
                            keyField={(doc) => doc.id}
                            emptyMessage="No Vault files match your filters."
                            columns={[
                                {
                                    key: "fileName",
                                    label: "File",
                                    render: (doc) => (
                                        <div className="flex items-center gap-3">
                                            <div className="flex h-9 w-9 shrink-0 items-center justify-center rounded-lg bg-[var(--surface-2)]">
                                                <FileText className="h-4 w-4 text-[var(--primary)]" />
                                            </div>
                                            <div>
                                                <p className="type-body-bold text-[var(--text)]">{doc.fileName}</p>
                                                <p className="text-xs text-[var(--text-muted)]">{VAULT_CATEGORIES.find((category) => category.value === doc.vaultCategory)?.label ?? "Other"}</p>
                                            </div>
                                        </div>
                                    ),
                                },
                                {
                                    key: "employee",
                                    label: "Employee",
                                    render: (doc) => <span className="type-body text-[var(--text-muted)]">{doc.employeeId ? employeeNameById[doc.employeeId] ?? "Unknown" : "-"}</span>,
                                },
                                {
                                    key: "storage",
                                    label: "Storage",
                                    render: (doc) => (
                                        <div className="flex w-fit items-center gap-1.5 rounded-full border border-[var(--border)] bg-[var(--surface-2)] px-2 py-1">
                                            {doc.driveFileId ? <Cloud className="h-3 w-3 text-[var(--primary)]" /> : <HardDrive className="h-3 w-3 text-[var(--text-muted)]" />}
                                            <span className="text-[10px] font-black uppercase text-[var(--text-muted)]">{doc.driveFileId ? "Google account" : "This device"}</span>
                                        </div>
                                    ),
                                },
                                {
                                    key: "date",
                                    label: "Added",
                                    render: (doc) => <span className="type-body text-[var(--text-muted)]">{format(new Date(doc.createdAt), "d MMM yyyy")}</span>,
                                },
                                {
                                    key: "actions",
                                    label: "",
                                    align: "right",
                                    render: (doc) => (
                                        <div className="flex items-center justify-end gap-1">
                                            <Button variant="ghost" size="sm" className="h-9 w-9 p-0" onClick={() => void handlePreview(doc)}>
                                                <Eye className="h-4 w-4 text-[var(--primary)]" />
                                            </Button>
                                            {vaultUploadsAllowed ? (
                                                <Button
                                                    variant="ghost"
                                                    size="sm"
                                                    className="h-9 w-9 p-0"
                                                    disabled={deletingDocumentId === doc.id}
                                                    onClick={() => void handleDeleteVaultDocument(doc)}
                                                >
                                                    <Trash2 className="h-4 w-4 text-[var(--text-muted)]" />
                                                </Button>
                                            ) : null}
                                        </div>
                                    ),
                                },
                            ]}
                        />
                    )}
                </div>
                {hasAnyContent && (
                    <aside className="ultrawide-panel hidden 2xl:block">
                        <Card className="glass-panel sticky top-0 border-none p-5">
                            <div className="space-y-4">
                                <div className="flex items-center gap-2 text-sm font-semibold text-[var(--text)]">
                                    <History className="h-4 w-4 text-[var(--primary)]" />
                                    One documentation hub
                                </div>
                                <p className="text-sm text-[var(--text-muted)]">
                                    This screen keeps payslips, contracts, exports, and uploaded records together so nothing feels split across the app.
                                </p>
                                {activeTab === "Contracts" && (
                                    <div className="space-y-2 rounded-2xl border border-[var(--border)] bg-[var(--surface-2)]/60 p-4">
                                        <div className="flex items-center gap-2 text-sm font-semibold text-[var(--text)]">
                                            <Upload className="h-4 w-4 text-[var(--primary)]" />
                                            Signed copy workflow
                                        </div>
                                        <p className="text-sm text-[var(--text-muted)]">
                                            Use the contract draft first. After you print and sign the final version, upload the signed copy here so it stays with the rest of the employee record.
                                        </p>
                                    </div>
                                )}
                                {activeTab === "Vault" && (
                                    <div className="space-y-2 rounded-2xl border border-[var(--border)] bg-[var(--surface-2)]/60 p-4">
                                        <div className="flex items-center gap-2 text-sm font-semibold text-[var(--text)]">
                                            <Cloud className="h-4 w-4 text-[var(--primary)]" />
                                            Vault storage
                                        </div>
                                        <p className="text-sm text-[var(--text-muted)]">
                                            Existing uploaded files always stay visible here. Pro unlocks new uploads for contracts, employee paperwork, and compliance records.
                                        </p>
                                    </div>
                                )}
                            </div>
                        </Card>
                    </aside>
                )}
            </div>

            {isGeneratingPreview && (
                <div className="fixed bottom-6 right-6 z-50 flex items-center justify-center rounded-full bg-[var(--primary)] p-4 text-white shadow-2xl animate-pulse">
                    Generating preview...
                </div>
            )}

            {previewUrl && (
                <DocumentPreview
                    url={previewUrl}
                    fileName={previewFileName ?? previewDoc?.fileName}
                    onClose={closePreview}
                    onDownload={() => {
                        const anchor = document.createElement("a");
                        anchor.href = previewUrl;
                        anchor.download = previewFileName ?? previewDoc?.fileName ?? "document.pdf";
                        document.body.appendChild(anchor);
                        anchor.click();
                        document.body.removeChild(anchor);
                    }}
                />
            )}
        </>
    );
}

"use client";

import * as React from "react";
import Link from "next/link";
import { useRouter, useParams, useSearchParams } from "next/navigation";
import {
    ArrowLeft, User, Clock, FileText, Palmtree,
    Pencil, Trash2, Loader2, FolderOpen
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardContent } from "@/components/ui/card";
import { EmployeeLeaveTab } from "@/components/employees/employee-leave-tab";
import {
    getContractsForEmployee, getEmployee, getLeaveCarryOversForEmployee, getPayslipsForEmployee, getLeaveForEmployee, getSettings,
    deletePayslip
} from "@/lib/storage";
import { Employee, LeaveCarryOver, PayslipInput, LeaveRecord, Contract, CustomLeaveType, EmployerSettings } from "@/lib/schema";
import { calculatePayslip } from "@/lib/calculator";
import { format } from "date-fns";
import { filterRecordsForArchiveWindow, getArchiveUpgradeHref, getArchiveUpgradeLabel, getArchiveUpgradeMessage } from "@/lib/archive";
import { canBrowseLeaveHistory, canUseAdvancedLeaveFeatures, canUseDocumentsHub, getUserPlan } from "@/lib/entitlements";
import { PLANS, type PlanConfig } from "@/config/plans";

type Tab = "profile" | "history" | "leave" | "documents";

const TABS: { id: Tab; label: string; icon: React.ElementType }[] = [
    { id: "profile", label: "Profile", icon: User },
    { id: "history", label: "Pay History", icon: Clock },
    { id: "leave", label: "Leave", icon: Palmtree },
    { id: "documents", label: "Documents", icon: FileText },
];

const PROFILE_FIGURE_GRID = "grid grid-cols-[minmax(0,1fr)_4.25rem_6rem_6rem] gap-x-3 sm:grid-cols-[minmax(0,1fr)_5rem_6.75rem_7rem]";
const SHELL_PANEL_CLASS = "rounded-[22px] border border-[var(--border)] bg-[var(--surface-1)] shadow-[0_1px_2px_rgba(16,24,40,0.04)]";

function formatRand(value: number) {
    return `R ${value.toFixed(2)}`;
}

function formatIdNumber(idNumber: string) {
    if (idNumber.length !== 13) return idNumber;
    return `${idNumber.slice(0, 6)} ${idNumber.slice(6, 10)} ${idNumber.slice(10)}`;
}

function EmployeeDetailContent() {
    const router = useRouter();
    const params = useParams<{ id: string }>();
    const searchParams = useSearchParams();
    const id = params?.id ?? "";

    const [activeTab, setActiveTab] = React.useState<Tab>("profile");
    const [employee, setEmployee] = React.useState<Employee | null>(null);
    const [payslips, setPayslips] = React.useState<PayslipInput[]>([]);
    const [leaveRecords, setLeaveRecords] = React.useState<LeaveRecord[]>([]);
    const [leaveCarryOvers, setLeaveCarryOvers] = React.useState<LeaveCarryOver[]>([]);
    const [contracts, setContracts] = React.useState<Contract[]>([]);
    const [customLeaveTypes, setCustomLeaveTypes] = React.useState<CustomLeaveType[]>([]);
    const [employerSettings, setEmployerSettings] = React.useState<EmployerSettings | null>(null);
    const [loading, setLoading] = React.useState(true);
    const [currentPlan, setCurrentPlan] = React.useState<PlanConfig>(PLANS.free);
    const [showLeaveTab, setShowLeaveTab] = React.useState(false);
    const [showDocumentsTab, setShowDocumentsTab] = React.useState(false);
    const [advancedLeaveEnabled, setAdvancedLeaveEnabled] = React.useState(false);
    const [deleteConfirmId, setDeleteConfirmId] = React.useState<string | null>(null);
    const [showDeleteConfirm, setShowDeleteConfirm] = React.useState(false);
    const [deleteConfirmText, setDeleteConfirmText] = React.useState("");

    const handleDeleteEmployee = async () => {
        if (!id) return;
        setLoading(true);
        try {
            const { deleteEmployee } = await import('@/lib/storage');
            await deleteEmployee(id);
            router.push("/employees");
        } catch (e) {
            console.error(e);
            setLoading(false);
            alert("Failed to delete employee.");
        }
    };

    React.useEffect(() => {
        async function load() {
            if (!id) return;
            const [emp, ps, leave, carryOvers, employeeContracts, settings] = await Promise.all([
                getEmployee(id),
                getPayslipsForEmployee(id),
                getLeaveForEmployee(id),
                getLeaveCarryOversForEmployee(id),
                getContractsForEmployee(id),
                getSettings(),
            ]);
            if (!emp) { router.push("/employees"); return; }
            setEmployee(emp);
            setPayslips([...ps].sort(
                (a, b) => new Date(b.payPeriodEnd).getTime() - new Date(a.payPeriodEnd).getTime()
            ));
            setLeaveRecords(leave);
            setLeaveCarryOvers(carryOvers);
            setContracts(employeeContracts);
            setCustomLeaveTypes(settings.customLeaveTypes ?? []);
            setEmployerSettings(settings);
            const plan = getUserPlan(settings);
            const allowLeave = canBrowseLeaveHistory(plan);
            const allowDocuments = canUseDocumentsHub(plan);
            setCurrentPlan(plan);
            setShowLeaveTab(allowLeave);
            setShowDocumentsTab(allowDocuments);
            setAdvancedLeaveEnabled(canUseAdvancedLeaveFeatures(plan));
            setLoading(false);

            const visibleTabs = TABS.filter((tab) => (tab.id !== "leave" || allowLeave) && (tab.id !== "documents" || allowDocuments));
            const tabParam = searchParams?.get("tab") as Tab | null;
            if (tabParam && visibleTabs.some((tab) => tab.id === tabParam)) {
                setActiveTab(tabParam);
            }
        }
        load();
    }, [id, router, searchParams]);



    const handleDeletePayslip = async (psId: string) => {
        await deletePayslip(psId);
        setDeleteConfirmId(null);
        setPayslips(prev => prev.filter(p => p.id !== psId));
    };

    const payslipArchiveResult = React.useMemo(
        () => filterRecordsForArchiveWindow(payslips, currentPlan, (record) => record.payPeriodEnd),
        [currentPlan, payslips],
    );
    const visiblePayslips = payslipArchiveResult.visible;
    const archiveUpgradeHref = getArchiveUpgradeHref(currentPlan.id);
    const archiveUpgradeLabel = getArchiveUpgradeLabel(currentPlan.id);

    if (loading) {
        return (
            <div className="min-h-screen flex flex-col" style={{ backgroundColor: "var(--bg)" }}>
                <div className="mb-6 rounded-2xl border border-[var(--border)] bg-[var(--surface-1)] p-4 shadow-[var(--shadow-sm)]">
                    <div className="max-w-4xl mx-auto w-full flex items-center gap-3">
                        <div className="h-9 w-9 rounded-xl bg-[var(--surface-2)] animate-pulse" />
                        <div className="h-9 w-9 rounded-xl bg-[var(--surface-2)] animate-pulse" />
                        <div className="h-4 w-32 bg-[var(--surface-2)] animate-pulse rounded" />
                    </div>
                </div>
                <main className="flex-1 max-w-4xl mx-auto w-full px-4 py-6 space-y-4">
                    <div className="h-16 w-full rounded-2xl bg-[var(--surface-1)] animate-pulse" />
                    <div className="h-48 w-full rounded-2xl bg-[var(--surface-1)] animate-pulse" />
                </main>
            </div>
        );
    }

    if (!employee) return null;

    const visibleTabs = TABS.filter((tab) => (tab.id !== "leave" || showLeaveTab) && (tab.id !== "documents" || showDocumentsTab));
    const formattedStartDate = employee.startDate ? format(new Date(employee.startDate), "dd MMM yyyy") : "Not set";
    const employeeRole = employee.role || "Domestic Worker";
    const latestPayslip = payslips[0] ?? null;
    const latestBreakdown = latestPayslip ? calculatePayslip(latestPayslip) : null;
    const now = new Date();
    const defaultPeriodStart = new Date(now.getFullYear(), now.getMonth(), 1);
    const defaultPeriodEnd = new Date(now.getFullYear(), now.getMonth() + 1, 0);
    const periodStart = latestPayslip ? new Date(latestPayslip.payPeriodStart) : defaultPeriodStart;
    const periodEnd = latestPayslip ? new Date(latestPayslip.payPeriodEnd) : defaultPeriodEnd;
    const monthLabel = new Intl.DateTimeFormat("en-ZA", { month: "long", year: "numeric" }).format(periodEnd);
    const periodLabel = `${periodStart.toLocaleDateString("en-ZA", { day: "2-digit", month: "short" })} - ${periodEnd.toLocaleDateString("en-ZA", { day: "2-digit", month: "short", year: "numeric" })}`;
    const employerName = employerSettings?.employerName?.trim() || "Employer details not added";
    const employerAddress = employerSettings?.employerAddress?.trim() || "Add employer details in Settings";
    const employerPhone = employerSettings?.phone?.trim();
    const employeePhone = employee.phone?.trim() || "Phone not added";
    const employeeId = employee.idNumber?.trim() ? `ID ${formatIdNumber(employee.idNumber)}` : "ID not added";
    const monthPrimaryLine = latestPayslip ? `${latestPayslip.daysWorked} days worked` : "No payslip created yet";
    const monthSecondaryLine = latestPayslip ? `${latestPayslip.ordinaryHours} ordinary hours` : "Create a payslip to show totals";

    return (
        <div className="min-h-screen flex flex-col" style={{ backgroundColor: "var(--bg)" }}>
            {/* Header */}
            <div className="border-b border-[var(--border)] bg-[var(--surface-1)]/95 px-4 py-4 backdrop-blur-sm">
                <div className="mx-auto flex max-w-4xl items-start gap-3">
                    <Link href="/employees">
                        <button
                            aria-label="Back to employees"
                            className="mt-0.5 flex h-10 w-10 items-center justify-center rounded-xl transition-colors hover:bg-[var(--surface-2)]"
                            style={{ color: "var(--text-muted)" }}
                        >
                            <ArrowLeft className="h-4 w-4" />
                        </button>
                    </Link>
                    <div className="min-w-0">
                        <p className="text-[10px] font-bold uppercase tracking-[0.18em]" style={{ color: "var(--text-muted)" }}>
                            <Link href="/employees" className="hover:underline">Employees</Link>
                        </p>
                        <h1 className="mt-1 text-xl font-black tracking-tight" style={{ color: "var(--text)" }}>
                            {employee.name}
                        </h1>
                        <p className="mt-1 text-sm" style={{ color: "var(--text-muted)" }}>
                            Employment record
                        </p>
                    </div>
                </div>
            </div>

            <main className="mx-auto flex w-full max-w-4xl flex-1 flex-col space-y-5 px-4 py-6 pb-24">
                <section className="overflow-hidden rounded-[30px] border border-[var(--border-strong)] bg-[var(--surface-1)] shadow-[0_20px_50px_rgba(16,24,40,0.10)]">
                    <div
                        className="border-b border-[var(--border)] px-5 py-4"
                        style={{ background: "linear-gradient(135deg, rgba(0, 122, 77, 0.10) 0%, rgba(196, 122, 28, 0.08) 100%)" }}
                    >
                        <div className="flex items-center justify-between gap-3">
                            <div>
                                <p className="text-[10px] font-black uppercase tracking-[0.18em]" style={{ color: "var(--text-muted)" }}>
                                    Employee Record
                                </p>
                            </div>
                            {latestPayslip && (
                                <p className="rounded-full border border-[var(--focus)]/20 bg-white/70 px-3 py-1.5 text-xs font-semibold shadow-sm" style={{ color: "var(--text)" }}>
                                    Latest: {monthLabel}
                                </p>
                            )}
                        </div>

                        <div className="mt-4 flex gap-1 rounded-2xl border border-[var(--border)] bg-white/55 p-1">
                            {visibleTabs.map(({ id: tabId, label, icon: Icon }) => {
                                const active = activeTab === tabId;
                                return (
                                    <button
                                        key={tabId}
                                        onClick={() => setActiveTab(tabId)}
                                        aria-pressed={active}
                                        className="flex-1 flex items-center justify-center gap-2 rounded-xl px-3 py-2 text-[10px] font-black uppercase tracking-[0.14em] transition-all duration-200"
                                        style={{
                                            backgroundColor: active ? "var(--primary)" : "transparent",
                                            color: active ? "#ffffff" : "var(--text-muted)",
                                            boxShadow: active ? "var(--shadow-sm)" : "none",
                                        }}
                                    >
                                        <Icon className="h-4 w-4" />
                                        {label}
                                    </button>
                                );
                            })}
                        </div>
                    </div>

                    <div className="animate-fade-in p-4 sm:p-5">
                        {/* PROFILE TAB */}
                        {activeTab === "profile" && (
                            <section>
                                <div className="flex items-start justify-between gap-4 border-b border-[var(--border)] pb-4">
                                    <div className="flex items-center gap-4">
                                        <div className="flex h-12 w-12 shrink-0 items-center justify-center rounded-2xl bg-[var(--surface-2)] text-[var(--primary)] uppercase font-black text-xl border border-[var(--border)]">
                                            {employee.name.substring(0, 2)}
                                        </div>
                                        <div>
                                            <h2 className="font-[family:var(--font-serif)] text-xl font-semibold" style={{ color: "var(--text)" }}>
                                                {employee.name}
                                            </h2>
                                            <p className="mt-1 text-sm font-semibold" style={{ color: "var(--text-muted)" }}>
                                                {employeeRole}
                                            </p>
                                        </div>
                                    </div>
                                    <div className="flex flex-col items-end gap-2 shrink-0">
                                        {!showDeleteConfirm ? (
                                            <>
                                                <Link href={`/employees/${id}/edit`}>
                                                    <Button variant="outline" size="sm" className="w-[140px] h-9 gap-2 font-bold px-3 justify-start">
                                                        <Pencil className="h-3.5 w-3.5" /> Edit details
                                                    </Button>
                                                </Link>
                                                <Button
                                                    variant="ghost"
                                                    size="sm"
                                                    onClick={() => setShowDeleteConfirm(true)}
                                                    className="w-[140px] h-9 gap-2 rounded-[10px] border border-red-200 bg-red-50 text-xs font-bold text-red-700 hover:bg-red-100 hover:text-red-800 justify-start px-3"
                                                >
                                                    <Trash2 className="h-3.5 w-3.5" /> Delete employee
                                                </Button>
                                            </>
                                        ) : (
                                            <div className="flex flex-col gap-3 rounded-[14px] border border-red-200 bg-red-50 p-3 w-[260px] text-left">
                                                <p className="text-xs font-bold text-red-800 leading-tight">This will delete all payslips and leave records.</p>
                                                <div className="space-y-1.5">
                                                    <p className="text-[10px] uppercase tracking-wider font-semibold text-red-700">Type DELETE to confirm:</p>
                                                    <Input
                                                        type="text"
                                                        value={deleteConfirmText}
                                                        onChange={(e) => setDeleteConfirmText(e.target.value)}
                                                        placeholder="DELETE"
                                                        className="h-8 text-xs bg-white border-red-200 focus-visible:ring-red-500 uppercase"
                                                    />
                                                </div>
                                                <div className="flex gap-2">
                                                    <Button
                                                        variant="outline"
                                                        size="sm"
                                                        onClick={() => {
                                                            setShowDeleteConfirm(false);
                                                            setDeleteConfirmText("");
                                                        }}
                                                        className="h-8 flex-1 text-xs font-bold"
                                                    >
                                                        Cancel
                                                    </Button>
                                                    <Button
                                                        size="sm"
                                                        disabled={deleteConfirmText !== "DELETE"}
                                                        onClick={handleDeleteEmployee}
                                                        className="h-8 flex-1 bg-red-600 text-xs font-bold text-white hover:bg-red-700 disabled:opacity-50"
                                                    >
                                                        Delete
                                                    </Button>
                                                </div>
                                            </div>
                                        )}
                                    </div>
                                </div>

                                <div className="mt-4 grid gap-3 sm:grid-cols-3">
                                    <ProfileInfoBlock
                                        label="Employer"
                                        value={employerName}
                                        detail={
                                            <>
                                                <p>{employerAddress}</p>
                                                {employerPhone ? <p>{employerPhone}</p> : null}
                                            </>
                                        }
                                    />
                                    <ProfileInfoBlock
                                        label="Employee"
                                        value={employee.name}
                                        detail={
                                            <>
                                                <p>{employeeRole}</p>
                                                <p>{employeeId}</p>
                                                <p>{employeePhone}</p>
                                                <p>Started {formattedStartDate}</p>
                                                <p>{employee.frequency} pay schedule</p>
                                            </>
                                        }
                                    />
                                    <ProfileInfoBlock
                                        label="Month"
                                        value={monthLabel}
                                        detail={
                                            <>
                                                <p>{monthPrimaryLine}</p>
                                                <p>{monthSecondaryLine}</p>
                                                <p>{`${employee.ordinaryHoursPerDay} hours/day ┬╖ R${employee.hourlyRate.toFixed(2)}/hr`}</p>
                                            </>
                                        }
                                    />
                                </div>

                                <div className="mt-4 rounded-[22px] border border-[var(--border)] p-4" style={{ background: "linear-gradient(180deg, rgba(255, 252, 248, 0.96) 0%, rgba(0, 122, 77, 0.03) 100%)" }}>
                                    <div className={`${PROFILE_FIGURE_GRID} border-b border-[var(--border)] pb-2 text-[10px] font-black uppercase tracking-[0.16em]`} style={{ color: "var(--text-muted)" }}>
                                        <span>Description</span>
                                        <span className="text-right">Hours</span>
                                        <span className="text-right">Rate</span>
                                        <span className="text-right">Total</span>
                                    </div>

                                    {latestPayslip && latestBreakdown ? (
                                        <div className="space-y-1 pt-2">
                                            <ProfileFigureRow
                                                label="Ordinary Hours"
                                                hours={`${latestPayslip.ordinaryHours}h`}
                                                rate={`${formatRand(latestBreakdown.hourlyRate)}/hr`}
                                                total={formatRand(latestBreakdown.ordinaryPay)}
                                            />
                                            <ProfileFigureRow label="Gross Earnings" hours="" rate="" total={formatRand(latestBreakdown.grossPay)} bold />
                                            <ProfileFigureRow label="UIF (Employee 1%)" hours="" rate="" total={`- ${formatRand(latestBreakdown.deductions.uifEmployee)}`} />
                                            <ProfileFigureRow label="Total Deductions" hours="" rate="" total={formatRand(latestBreakdown.deductions.total)} bold />
                                        </div>
                                    ) : (
                                        <div className="pt-3">
                                            <p className="text-sm font-semibold" style={{ color: "var(--text)" }}>
                                                No payslip yet for this employee.
                                            </p>
                                            <p className="mt-1 text-sm" style={{ color: "var(--text-muted)" }}>
                                                Create the first payslip to show gross pay, UIF deductions, and net amount here.
                                            </p>
                                            <Link href={`/wizard?empId=${id}`} className="mt-3 inline-flex">
                                                <Button className="bg-[var(--primary)] text-white font-bold hover:bg-[var(--primary-hover)]">
                                                    Create Payslip
                                                </Button>
                                            </Link>
                                        </div>
                                    )}
                                </div>

                                <div className="mt-3 rounded-[22px] border border-[var(--focus)]/20 p-4" style={{ background: "linear-gradient(135deg, rgba(0, 122, 77, 0.08) 0%, rgba(196, 122, 28, 0.08) 100%)" }}>
                                    <div className="flex items-end justify-between gap-4">
                                        <div>
                                            <p className="text-[10px] font-black uppercase tracking-[0.18em]" style={{ color: "var(--text-muted)" }}>
                                                Net amount paid
                                            </p>
                                            <p className="mt-1 text-sm" style={{ color: "var(--text-muted)" }}>
                                                {latestPayslip ? "Based on the latest payslip above." : "Will appear after the first payslip is created."}
                                            </p>
                                        </div>
                                        <p className="font-[family:var(--font-serif)] text-2xl font-semibold tabular-nums" style={{ color: "var(--primary-pressed)" }}>
                                            {latestBreakdown ? formatRand(latestBreakdown.netPay) : "R 0.00"}
                                        </p>
                                    </div>
                                </div>


                            </section>
                        )}

                        {/* PAY HISTORY TAB */}
                        {activeTab === "history" && (
                            <div className="space-y-3">
                                {visiblePayslips.length === 0 ? (
                                    <Card className={`${SHELL_PANEL_CLASS} border-dashed border-2`}>
                                        <CardContent className="p-10 text-center">
                                            <Clock className="h-10 w-10 mx-auto mb-3 text-[var(--text-muted)]" strokeWidth={1.5} />
                                            <p className="font-bold text-sm mb-1" style={{ color: "var(--text)" }}>
                                                {payslipArchiveResult.hiddenCount > 0 ? "Older payslips are hidden on this plan" : "No payslips yet"}
                                            </p>
                                            <p className="text-xs mb-4" style={{ color: "var(--text-muted)" }}>
                                                {payslipArchiveResult.hiddenCount > 0
                                                    ? "Upgrade to browse the full payslip history here."
                                                    : `Generate the first payslip for ${employee.name}.`}
                                            </p>
                                            <Link href={`/wizard?empId=${id}`}>
                                                <Button className="bg-[var(--primary)] text-white font-bold hover:brightness-95">Create Payslip</Button>
                                            </Link>
                                        </CardContent>
                                    </Card>
                                ) : (
                                    visiblePayslips.map((ps, i) => {
                                        const calc = calculatePayslip(ps);
                                        return (
                                            <Card key={ps.id} className={`${SHELL_PANEL_CLASS} cursor-pointer animate-slide-up`} style={{ animationDelay: `${i * 50}ms` }}>
                                                <CardContent className="p-4" onClick={() => router.push(`/preview?payslipId=${ps.id}&empId=${id}`)}>
                                                    <div className="flex items-center justify-between gap-3">
                                                        <div>
                                                            <p className="font-bold text-sm" style={{ color: "var(--text)" }}>
                                                                {format(new Date(ps.payPeriodStart), "MMM d")} ΓÇô {format(new Date(ps.payPeriodEnd), "MMM d, yyyy")}
                                                            </p>
                                                            <p className="text-xs tabular-nums" style={{ color: "var(--text-muted)" }}>
                                                                Net: <strong>R{calc.netPay.toFixed(2)}</strong> ┬╖ Gross: R{calc.grossPay.toFixed(2)}
                                                            </p>
                                                            <p className="mt-1 text-[11px] font-bold uppercase tracking-wider text-[var(--primary)]">
                                                                Open payslip
                                                            </p>
                                                        </div>
                                                        <div className="flex items-center gap-1.5 shrink-0">
                                                            {deleteConfirmId === ps.id ? (
                                                                <>
                                                                    <span className="text-xs font-bold text-red-500">Delete?</span>
                                                                    <Button size="sm" variant="ghost" className="h-8 px-2 text-xs font-bold text-red-500 hover:bg-red-50"
                                                                        onClick={(event) => { event.stopPropagation(); handleDeletePayslip(ps.id); }}>Yes</Button>
                                                                    <Button size="sm" variant="ghost" className="h-8 px-2 text-xs font-bold"
                                                                        onClick={(event) => { event.stopPropagation(); setDeleteConfirmId(null); }}>No</Button>
                                                                </>
                                                            ) : (
                                                                <Button variant="outline" size="sm" className="h-10 px-3 text-xs font-bold text-red-700 border-red-200 hover:text-red-800 hover:bg-red-50"
                                                                        onClick={(event) => { event.stopPropagation(); setDeleteConfirmId(ps.id); }}>
                                                                        <Trash2 className="h-4 w-4" />
                                                                        <span className="ml-1">Delete</span>
                                                                    </Button>
                                                            )}
                                                        </div>
                                                    </div>
                                                </CardContent>
                                            </Card>
                                        );
                                    })
                                )}
                                {visiblePayslips.length > 0 && (
                                    <Link href={`/wizard?empId=${id}`}>
                                        <Button className="w-full bg-[var(--primary)] text-white font-bold hover:brightness-95 mt-2">
                                            + New Payslip
                                        </Button>
                                    </Link>
                                )}
                                {payslipArchiveResult.hiddenCount > 0 && (
                                    <div className="rounded-2xl border border-[var(--primary)]/20 bg-[var(--primary)]/8 px-4 py-4">
                                        <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
                                            <div>
                                                <p className="text-sm font-bold text-[var(--text)]">{getArchiveUpgradeMessage(currentPlan.id, payslipArchiveResult.hiddenCount, "payslip")}</p>
                                            </div>
                                            <Link href={archiveUpgradeHref}>
                                                <Button className="bg-[var(--primary)] text-white hover:bg-[var(--primary-hover)]">{archiveUpgradeLabel}</Button>
                                            </Link>
                                        </div>
                                    </div>
                                )}
                            </div>
                        )}

                        {/* LEAVE TAB */}
                        {activeTab === "leave" && (
                            <EmployeeLeaveTab
                                employee={employee}
                                leaveRecords={leaveRecords}
                                leaveCarryOvers={leaveCarryOvers}
                                contracts={contracts}
                                customLeaveTypes={customLeaveTypes}
                                currentPlan={currentPlan}
                                advancedLeaveEnabled={advancedLeaveEnabled}
                                variant="embedded"
                            />
                        )}

                        {/* DOCUMENTS TAB */}
                        {activeTab === "documents" && (
                            <Card className={SHELL_PANEL_CLASS}>
                                <CardContent className="p-5 space-y-3">
                                    <h3 className="text-[10px] font-black uppercase tracking-widest mb-4" style={{ color: "var(--text-muted)" }}>
                                        Employee documents
                                    </h3>
                                    <Link href={`/documents?tab=contracts`}>
                                        <Button className="w-full h-12 justify-start gap-3 bg-[var(--primary)] text-white hover:bg-[var(--primary-hover)] font-bold">
                                            <FolderOpen className="h-4 w-4" />
                                            Open the documents hub
                                        </Button>
                                    </Link>
                                    <p className="text-sm text-[var(--text-muted)]">
                                        Contracts, certificates, exports, and older records should live in one documents area instead of being scattered through employee pages.
                                    </p>
                                    <Link href={`/contracts/new?employeeId=${id}`}>
                                        <Button variant="outline" className="w-full h-11 font-bold">
                                            Start a contract draft
                                        </Button>
                                    </Link>
                                </CardContent>
                            </Card>
                        )}
                    </div>
                </section>
            </main>
        </div>
    );
}

function ProfileInfoBlock({ label, value, detail }: { label: string; value: string; detail?: React.ReactNode }) {
    return (
        <div
            className="rounded-[18px] border border-[var(--border)] px-4 py-3 shadow-[0_1px_2px_rgba(16,24,40,0.04)]"
            style={{ background: "linear-gradient(180deg, rgba(255, 255, 255, 0.98) 0%, rgba(0, 122, 77, 0.03) 100%)" }}
        >
            <p className="text-[10px] font-black uppercase tracking-[0.16em]" style={{ color: "var(--primary)" }}>
                {label}
            </p>
            <p className="mt-2 text-sm font-semibold" style={{ color: "var(--text)" }}>
                {value}
            </p>
            {detail ? (
                <div className="mt-2 space-y-1 text-xs" style={{ color: "var(--text-muted)" }}>
                    {detail}
                </div>
            ) : null}
        </div>
    );
}

function ProfileFigureRow({ label, hours, rate, total, bold = false }: { label: string; hours: string; rate: string; total: string; bold?: boolean }) {
    return (
        <div className={`${PROFILE_FIGURE_GRID} items-baseline py-2 text-[13px] sm:text-sm`}>
            <span className={`pr-2 ${bold ? "font-semibold" : ""}`} style={{ color: bold ? "var(--text)" : "var(--text-muted)" }}>
                {label}
            </span>
            <span className="text-right tabular-nums whitespace-nowrap" style={{ color: "var(--text-muted)" }}>
                {hours}
            </span>
            <span className="text-right tabular-nums whitespace-nowrap" style={{ color: "var(--text-muted)" }}>
                {rate}
            </span>
            <span className={`text-right tabular-nums whitespace-nowrap ${bold ? "font-semibold" : ""}`} style={{ color: "var(--text)" }}>
                {total}
            </span>
        </div>
    );
}
export default function EmployeeDetailPage() {
    return (
        <React.Suspense
            fallback={
                <div className="min-h-screen flex items-center justify-center" style={{ backgroundColor: "var(--bg)" }}>
                    <Loader2 className="h-8 w-8 animate-spin" style={{ color: "var(--primary)" }} />
                </div>
            }
        >
            <EmployeeDetailContent />
        </React.Suspense>
    );
}

