function buildPaidLoginHref(planId: "standard" | "pro", billingCycle: BillingCycle): string {
    const params = new URLSearchParams({
        paidLogin: "1",
        next: `/upgrade?plan=${planId}&billing=${billingCycle}&pay=1`,
