            const currentSettings = await getSettings();
            setSettings(currentSettings as EmployerSettings);
            const requestedBilling = searchParams.get("billing");
            setBillingCycle(requestedBilling === "monthly" ? "monthly" : requestedBilling === "yearly" ? "yearly" : currentSettings.billingCycle === "monthly" ? "monthly" : "yearly");
        }
        void load();
    }, [searchParams]);

    const startCheckout = React.useCallback(async (planId: "standard" | "pro") => {
        setCheckoutError("");

        if (!hasStoredGoogleSession()) {
            router.push(buildPaidLoginHref(planId, billingCycle));
            return;
        }

        try {
            setCheckoutPlanId(planId);
            const checkout = await createCheckoutSession({ planId, billingCycle });
            window.location.href = checkout.authorizationUrl;
        } catch (error) {
            const message = error instanceof Error ? error.message : "Checkout could not be started.";
            setCheckoutError(message);
            toast(message);
            setCheckoutPlanId(null);
        }
    }, [billingCycle, router, toast]);

    React.useEffect(() => {
        if (!settings || hasAutoStartedCheckout.current) return;
        const requestedPlan = searchParams.get("plan");
        const shouldPayNow = searchParams.get("pay") === "1";
        if ((requestedPlan === "standard" || requestedPlan === "pro") && shouldPayNow) {
            const currentPlan = getUserPlan(settings);
            if (currentPlan.id !== requestedPlan) {
                hasAutoStartedCheckout.current = true;
                void startCheckout(requestedPlan);
            }
        }
    }, [searchParams, settings, startCheckout]);

    const currentPlan = settings ? getUserPlan(settings) : PLANS.free;

    if (!settings) {
        return null;
    }

    return (
        <div className="space-y-8 pb-20">
            <PageHeader
                title="Plans & billing"
                subtitle="Choose the level of Google-connected backup, archive depth, and household control you need."
            />

            <div className="mx-auto max-w-6xl space-y-10">
                <Card className="border-[var(--primary)] bg-[var(--primary)]/5">
                    <CardContent className="space-y-3 p-5 text-sm leading-relaxed" style={{ color: "var(--text-muted)" }}>
                        <p className="font-semibold" style={{ color: "var(--text)" }}>
                            Try Standard or Pro with a 14-day refund window.
                        </p>
                        <p className="font-semibold" style={{ color: "var(--text)" }}>
                            Paid access is confirmed through your Google sign-in, not by this browser alone.
                        </p>
                        <p>
                            If you are not signed into Google yet, choosing a paid plan starts paid login immediately, then LekkerLedger starts the Paystack checkout securely from the server.
                        </p>
                        <p>
                            You can stop renewal before the next billing period, and access continues until the end of the billing period you already paid for.
                        </p>
                    </CardContent>
                </Card>

                {checkoutError && (
                    <div className="rounded-2xl border px-4 py-3 text-sm font-medium" style={{ borderColor: "rgba(180,35,24,0.25)", backgroundColor: "rgba(180,35,24,0.06)", color: "var(--danger)" }}>
                        {checkoutError}
                    </div>
                )}

                <div className="flex flex-col items-center gap-10">
                    <MarketingBillingToggle 
                        billingCycle={billingCycle} 
                        onChange={setBillingCycle} 
                        align="center" 
                    />

                    <MarketingPlanCards 
                        billingCycle={billingCycle} 
                        currentPlanId={currentPlan.id as PlanId}
                        onSelect={(planId) => {
                            if (planId === "standard" || planId === "pro") {
                                void startCheckout(planId);
                            }
                        }}
                        isLoadingPlanId={checkoutPlanId}
                    />
                </div>

                <div className="grid gap-6 lg:grid-cols-[1.1fr_0.9fr]">
                    <Card className="border-[var(--border)]">
                        <CardContent className="space-y-4 p-6 text-sm">
                            <h3 className="type-h3" style={{ color: "var(--text)" }}>What changes on paid plans</h3>
                            <p className="leading-relaxed" style={{ color: "var(--text-muted)" }}>
                                Paid plans are for households that want less repeated admin: Google-connected backup across browsers and devices, exports, deeper archives, and cleaner annual paperwork. They are meant to cost less than the time or outside help it usually takes to reconstruct records later.
                            </p>
                            <p className="leading-relaxed" style={{ color: "var(--text-muted)" }}>
                                Standard is the paid plan for most households that want organised records, Google-connected backup, and annual paperwork. Pro is for households that want deeper history and more control, with multi-household support and unlimited employees when you need more headroom.
                            </p>
                        </CardContent>
                    </Card>

                    <Card className="border-[var(--primary)] bg-[var(--primary)]/5">
                        <CardContent className="space-y-4 p-6 text-sm">
                            <div className="flex items-center gap-3">
                                <div className="rounded-2xl bg-[var(--primary)] p-3 text-white">
                                    <ShieldCheck className="h-5 w-5" />
                                </div>
                                <h3 className="type-h3" style={{ color: "var(--text)" }}>Refunds and trust</h3>
                            </div>
                            <p className="leading-relaxed" style={{ color: "var(--text-muted)" }}>
                                If you request a refund within 14 days of purchase, we will refund you in full once we have verified the payment. The goal is to keep the decision low-risk, not to push hard-sell billing language through the app.
                            </p>
                            <p className="leading-relaxed" style={{ color: "var(--text-muted)" }}>
                                You can stop renewal before the next billing period, and access continues until the end of the billing period already paid for.
                            </p>
                            <Link href="/legal/refunds" className="inline-flex items-center gap-2 font-semibold text-[var(--primary)]">
                                View refund policy <ArrowRight className="h-4 w-4" />
                            </Link>
                        </CardContent>
                    </Card>
                </div>
            </div>
        </div>
    );
}

"use client";

// import "../pdf.worker.ts";

import * as React from "react";
import Link from "next/link";
import { useRouter, useSearchParams } from "next/navigation";
import { ArrowLeft, ArrowRight, Loader2, Check, Clock, Sparkles, AlertCircle, Info, CheckCircle2, AlertTriangle } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Stepper } from "@/components/ui/stepper";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { Switch } from "@/components/ui/switch";
import { StickyBottomBar } from "@/components/layout/sticky-bottom-bar";
import { getEmployees, savePayslip, getSecureTime, getSettings, getAllPayslips, deletePayslip, saveDocumentMeta } from "@/lib/storage";
import { Employee, PayslipInput, EmployerSettings } from "@/lib/schema";
import { format } from "date-fns";
import { calculatePayslip, NMW_RATE } from "@/lib/calculator";
import { useToast } from "@/components/ui/toast";
import { getHolidaysInRange } from "@/lib/holidays";
import { formatDateSafe } from "@/lib/utils";
import { canUseLeaveTracking, getUserPlan } from "@/lib/entitlements";

const STEPS = [
    { label: "Hours", description: "Ordinary & overtime" },
    { label: "Sundays & Holidays", description: "Special rates" },
    { label: "Deductions", description: "UIF & accommodation" },
    { label: "Review", description: "Final confirmation" },
];

const safeDate = (s: string): Date => {
    if (!s) return new Date();
    const d = new Date(s);
    return isNaN(d.getTime()) ? new Date() : d;
};

function WizardContent() {
    const router = useRouter();
    const searchParams = useSearchParams();
    const empId = searchParams?.get("empId");
    const { toast } = useToast();

    const [employee, setEmployee] = React.useState<Employee | null>(null);
    const [settings, setSettings] = React.useState<EmployerSettings | null>(null);
    const [loadingInitial, setLoadingInitial] = React.useState(true);
    const [currentStep, setCurrentStep] = React.useState<number>(0);
    const [loading, setLoading] = React.useState(false);
    const [duplicateId, setDuplicateId] = React.useState<string | null>(null);
    const [employerDetailsGate, setEmployerDetailsGate] = React.useState(false);

    const now = new Date();
    const defaultStart = formatDateSafe(new Date(now.getFullYear(), now.getMonth(), 1));
    const defaultEnd = formatDateSafe(new Date(now.getFullYear(), now.getMonth() + 1, 0));

    const [hours, setHours] = React.useState({ ordinary: "", overtime: "", sunday: "", holiday: "" });
    const [shortFallHours, setShortFallHours] = React.useState("");
    const [daysWorked, setDaysWorked] = React.useState("0");
    const [dates, setDates] = React.useState({ start: defaultStart, end: defaultEnd });

    // Automation States
    const [showShortfallHelper, setShowShortfallHelper] = React.useState(false);
    const [shortShiftCount, setShortShiftCount] = React.useState(0);
    const [totalWorkedInShortShifts, setTotalWorkedInShortShifts] = React.useState(0);

    const detectedHolidays = getHolidaysInRange(dates.start, dates.end);

    const applyHolidays = () => {
        const total = (detectedHolidays.length * 8).toString();
        setHours(prev => ({ ...prev, holiday: total }));
        toast(`Applied ${total} hours for ${detectedHolidays.length} holidays.`);
    };

    // Auto-calculate ordinary days (excluding Sundays) when period changes
    React.useEffect(() => {
        if (dates.start && dates.end) {
            const start = safeDate(dates.start);
            const end = safeDate(dates.end);

            // Prevent runaway loops if dates are invalid or start > end
            if (isNaN(start.getTime()) || isNaN(end.getTime()) || start > end) {
                setDaysWorked("0");
                return;
            }

            let count = 0;
            const cur = new Date(start);
            // Limit loop to prevent potential infinite if date logic bad
            let safety = 0;
            while (cur <= end && safety < 100) {
                if (cur.getDay() !== 0) count++; // Exclude Sundays
                cur.setDate(cur.getDate() + 1);
                safety++;
            }
            setDaysWorked(count.toString());
        }
    }, [dates.start, dates.end]);
    const [periodError, setPeriodError] = React.useState("");
    const [hoursError, setHoursError] = React.useState("");
    const [includeAccommodation, setIncludeAccommodation] = React.useState(false);
    const [accommodationCost, setAccommodationCost] = React.useState("");
    const leaveTrackingEnabled = settings ? canUseLeaveTracking(getUserPlan(settings)) : false;

    React.useEffect(() => {
        let active = true;
        async function load() {
            const [employees, s] = await Promise.all([getEmployees(), getSettings()]);
            if (!active) return;
            const emp = employees.find((e) => e.id === empId);
            if (emp) {
                setEmployee(emp);
            } else {
                router.push("/employees");
            }
            setSettings(s);
            setLoadingInitial(false);
        }
        load();
        return () => {
            active = false;
        };
    }, [empId, router]);

    const totalHours =
        (Number(hours.ordinary) || 0) +
        (Number(hours.overtime) || 0) +
        (Number(hours.sunday) || 0) +
        (Number(hours.holiday) || 0);

    const [leave, setLeave] = React.useState({ annual: "", sick: "", family: "" });

    const breakdown = employee
        ? calculatePayslip({
            id: "preview",
            householdId: employee.householdId ?? "default",
            employeeId: employee.id,
            payPeriodStart: safeDate(dates.start),
            payPeriodEnd: safeDate(dates.end),
            ordinaryHours: Number(hours.ordinary) || 0,
            overtimeHours: Number(hours.overtime) || 0,
            sundayHours: Number(hours.sunday) || 0,
            publicHolidayHours: Number(hours.holiday) || 0,
            daysWorked: Number(daysWorked) || 1,
            shortFallHours: Number(shortFallHours) || 0,
            hourlyRate: employee.hourlyRate,
            ordinarilyWorksSundays: employee.ordinarilyWorksSundays ?? false,
            ordinaryHoursPerDay: employee.ordinaryHoursPerDay ?? 8,
            includeAccommodation,
            accommodationCost: includeAccommodation && accommodationCost ? Number(accommodationCost) : undefined,
            otherDeductions: 0,
            annualLeaveTaken: leaveTrackingEnabled ? Number(leave.annual) || 0 : 0,
            sickLeaveTaken: leaveTrackingEnabled ? Number(leave.sick) || 0 : 0,
            familyLeaveTaken: leaveTrackingEnabled ? Number(leave.family) || 0 : 0,
            createdAt: new Date(),
        })
        : null;

    const doSave = React.useCallback(async () => {
        if (!employee) return;
        setLoading(true);
        try {
            // Validate against secure time before save
            const [_settingsCheck, nowSafe] = await Promise.all([getSettings(), getSecureTime()]);
            void _settingsCheck;
            void nowSafe;

            const payslipInput: PayslipInput = {
                id: crypto.randomUUID(),
                householdId: employee.householdId ?? "default",
                employeeId: employee.id,
                payPeriodStart: safeDate(dates.start),
                payPeriodEnd: safeDate(dates.end),
                ordinaryHours: Number(hours.ordinary) || 0,
                overtimeHours: Number(hours.overtime) || 0,
                sundayHours: Number(hours.sunday) || 0,
                publicHolidayHours: Number(hours.holiday) || 0,
                daysWorked: Number(daysWorked) || 1,
                shortFallHours: Number(shortFallHours) || 0,
                hourlyRate: employee.hourlyRate,
                ordinarilyWorksSundays: employee.ordinarilyWorksSundays ?? false,
                ordinaryHoursPerDay: employee.ordinaryHoursPerDay ?? 8,
                includeAccommodation,
                accommodationCost: includeAccommodation && accommodationCost ? Number(accommodationCost) : undefined,
                otherDeductions: 0,
                annualLeaveTaken: leaveTrackingEnabled ? Number(leave.annual) || 0 : 0,
                sickLeaveTaken: leaveTrackingEnabled ? Number(leave.sick) || 0 : 0,
                familyLeaveTaken: leaveTrackingEnabled ? Number(leave.family) || 0 : 0,
                createdAt: new Date(),
            };

            await savePayslip(payslipInput);

            await saveDocumentMeta({
                id: payslipInput.id,
                householdId: employee.householdId ?? "default",
                type: "payslip",
                employeeId: employee.id,
                fileName: `${employee.name.split(' ')[0]}_Payslip_${format(safeDate(dates.start), "MMM_yyyy")}.pdf`,
                source: "generated",
                createdAt: new Date().toISOString(),
            });

            // GA4 conversion tracking
            try {
                if (typeof window !== 'undefined' && 'gtag' in window) {
                    (window as Window & { gtag?: (...args: unknown[]) => void }).gtag?.('event', 'onboarding_complete');
                }
            } catch (e) {
                console.error('GA4 tracking failed:', e);
            }

            toast("Payslip generated successfully!");
            router.push(`/preview?payslipId=${payslipInput.id}&empId=${employee.id}`);
        } catch (err) {
            console.error(err);
            toast(`Failed to generate payslip. ${err instanceof Error ? err.message : String(err)}`);
        } finally {
            setLoading(false);
        }
    }, [employee, dates, hours, daysWorked, shortFallHours, includeAccommodation, accommodationCost, leave, router, toast]);

    const handleNext = async () => {
        if (currentStep === 0) {
            if (!dates.start || !dates.end) { setPeriodError("Please select the pay period."); return; }
            if (!hours.ordinary && !hours.overtime && !hours.sunday && !hours.holiday) {
                setHoursError("Please enter at least some hours worked.");
                return;
            }
            setPeriodError("");
            setHoursError("");
        }

        if (currentStep < STEPS.length - 1) {
            setCurrentStep((s) => s + 1);
            return;
        }

        // Save & navigate to preview ΓÇö check for duplicates first
        if (!employee) return;
        if (!settings?.employerName?.trim() || !settings?.employerAddress?.trim()) {
            setEmployerDetailsGate(true);
            return;
        }
        setLoading(true);

        try {
            const allPayslips = await getAllPayslips();
            const currentMonth = format(safeDate(dates.start), "yyyy-MM");
            const dup = allPayslips.find(
                p => p.employeeId === empId &&
                    format(new Date(p.payPeriodStart), "yyyy-MM") === currentMonth
            );
            if (dup) {
                setDuplicateId(dup.id);
                setLoading(false);
                return;
            }
        } catch (err) {
            console.error("Duplicate check failed:", err);
        }

        await doSave();
    };

    if (loadingInitial) {
        return (
            <div className="min-h-screen flex flex-col" style={{ backgroundColor: "var(--bg)" }}>
                <div className="mb-4 rounded-2xl border border-[var(--border)] bg-[var(--surface-1)] p-4 shadow-[var(--shadow-sm)]">
                    <div className="max-w-4xl mx-auto w-full flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <div className="h-9 w-9 rounded-xl bg-[var(--surface-2)] animate-pulse" />
                            <div className="space-y-2">
                                <div className="h-4 w-28 bg-[var(--surface-2)] animate-pulse rounded" />
                                <div className="h-3 w-20 bg-[var(--surface-2)] animate-pulse rounded" />
                            </div>
                        </div>
                    </div>
                </div>
                <main className="flex-1 max-w-4xl mx-auto w-full px-4 py-6 space-y-5 flex flex-col">
                    <div className="h-24 w-full rounded-2xl bg-[var(--surface-1)] animate-pulse border border-[var(--border)]" />
                    <div className="flex-1 w-full rounded-2xl bg-[var(--surface-1)] animate-pulse border border-[var(--border)]" />
                </main>
            </div>
        );
    }

    if (!employee) return null;

    return (
        <div className="min-h-screen flex flex-col" style={{ backgroundColor: "var(--bg)" }}>
            {/* Header */}
            <div className="mb-6 rounded-2xl border border-[var(--border)] bg-[var(--surface-1)] p-4 shadow-[var(--shadow-sm)]">
                <div className="max-w-4xl mx-auto w-full flex items-center justify-between">
                    <div className="flex items-center gap-3">
                        <Link href="/employees">
                            <button
                                aria-label="Back"
                                className="h-9 w-9 flex items-center justify-center rounded-xl transition-colors hover:bg-[var(--surface-2)]"
                                style={{ color: "var(--text-muted)" }}
                            >
                                <ArrowLeft className="h-4 w-4" />
                            </button>
                        </Link>
                        <div>
                            <h1 className="font-bold text-sm tracking-tight leading-tight" style={{ color: "var(--text)" }}>
                                Payslip Wizard
                            </h1>
                            <p className="text-xs leading-tight" style={{ color: "var(--text-muted)" }}>
                                {employee.name}
                            </p>
                        </div>
                    </div>
                    <span
                        className="text-xs font-semibold px-3 py-1 rounded-full bg-[var(--primary)]/10 text-[var(--focus)]"
                    >
                        Step {currentStep + 1}/{STEPS.length}
                    </span>
                </div>
            </div>

            <main className="flex-1 content-container">
                {/* Stepper */}
                <div
                    className="p-5 rounded-2xl"
                    style={{
                        backgroundColor: "var(--surface-1)",
                        border: "1px solid var(--border)",
                        boxShadow: "var(--shadow-sm)",
                    }}
                >
                    <Stepper steps={STEPS} currentStep={currentStep} />
                </div>
                {/* National Minimum Wage notice */}
                {employee.hourlyRate <= NMW_RATE && (
                    <Alert variant="warning">
                        <AlertDescription>
                            Using National Minimum Wage (R{NMW_RATE}/hr).
                        </AlertDescription>
                    </Alert>
                )}

                {/* Step Card */}
                <Card key={currentStep} className="animate-slide-right">
                    <CardHeader>
                        <CardTitle>{STEPS[currentStep].label}</CardTitle>
                        <CardDescription>{STEPS[currentStep].description}</CardDescription>
                    </CardHeader>

                    <CardContent className="space-y-5">
                        {/* STEP 0 ΓÇö Hours & Period */}
                        {currentStep === 0 && (
                            <div className="space-y-6">
                                <div className="grid grid-cols-2 gap-3">
                                    <div className="space-y-2">
                                        <Label htmlFor="start">Period Start</Label>
                                        <Input
                                            id="start"
                                            type="date"
                                            value={dates.start}
                                            onChange={(e) => setDates({ ...dates, start: e.target.value })}
                                            error={periodError || undefined}
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <Label htmlFor="end">Period End</Label>
                                        <Input
                                            id="end"
                                            type="date"
                                            value={dates.end}
                                            onChange={(e) => setDates({ ...dates, end: e.target.value })}
                                        />
                                    </div>
                                </div>

                                <div className="pt-4 space-y-5" style={{ borderTop: "1px solid var(--border)" }}>
                                    <div className="flex items-center justify-between">
                                        <h3 className="text-sm font-bold uppercase tracking-wider text-zinc-400 flex items-center gap-2">
                                            <Clock className="w-4 h-4 text-[var(--focus)]" />
                                            Work Schedule
                                        </h3>
                                        <div className="flex gap-2">
                                            {detectedHolidays.length > 0 && (
                                                <Button
                                                    variant="outline"
                                                    size="sm"
                                                    className="h-8 border-[var(--focus)]/30 text-[var(--focus)] bg-[var(--primary)]/5 hover:bg-[var(--primary)]/10 text-[10px] gap-1.5 px-2"
                                                    onClick={applyHolidays}
                                                >
                                                    <Sparkles className="w-3 h-3" />
                                                    Apply Holidays
                                                </Button>
                                            )}
                                        </div>
                                    </div>

                                    <div className="grid grid-cols-2 gap-4">
                                        <div className="space-y-2">
                                            <Label htmlFor="ordinary" className="text-xs">Ordinary Hours</Label>
                                            <Input
                                                id="ordinary"
                                                type="number"
                                                min="0"
                                                placeholder="160"
                                                value={hours.ordinary}
                                                onChange={(e) => setHours({ ...hours, ordinary: e.target.value })}
                                            />
                                        </div>
                                        <div className="space-y-2">
                                            <Label htmlFor="daysWorked" className="text-xs">Days Worked</Label>
                                            <Input
                                                id="daysWorked"
                                                type="number"
                                                min="0"
                                                placeholder="20"
                                                value={daysWorked}
                                                onChange={(e) => setDaysWorked(e.target.value)}
                                            />
                                        </div>
                                        <div className="space-y-2">
                                            <Label htmlFor="overtime" className="text-xs">Overtime (1.5x)</Label>
                                            <Input
                                                id="overtime"
                                                type="number"
                                                min="0"
                                                placeholder="0"
                                                value={hours.overtime}
                                                onChange={(e) => setHours({ ...hours, overtime: e.target.value })}
                                            />
                                        </div>
                                        <div className="space-y-2">
                                            <Label htmlFor="shortFallHours" className="text-xs">Shortfall (4-hr rule)</Label>
                                            <Input
                                                id="shortFallHours"
                                                type="number"
                                                min="0"
                                                placeholder="0"
                                                value={shortFallHours}
                                                onChange={(e) => setShortFallHours(e.target.value)}
                                            />
                                        </div>
                                    </div>

                                    {/* Hours error */}
                                    {hoursError && (
                                        <p className="text-xs text-red-500 font-medium">{hoursError}</p>
                                    )}

                                    {/* 4-Hour Rule Assistant */}
                                    <div className="p-4 rounded-xl border border-[var(--focus)]/10 bg-[var(--primary)]/[0.02] space-y-3">
                                        <div className="flex items-center justify-between">
                                            <div className="flex items-center gap-2">
                                                <Info className="w-3.5 h-3.5 text-[var(--focus)]" />
                                                <Label htmlFor="assistant-switch" className="text-[11px] font-bold text-zinc-300 uppercase tracking-tight cursor-pointer">4-Hour Rule Assistant</Label>
                                            </div>
                                            <Switch
                                                id="assistant-switch"
                                                checked={showShortfallHelper}
                                                onCheckedChange={setShowShortfallHelper}
                                            />
                                        </div>
                                        {showShortfallHelper && (
                                            <div className="space-y-3 pt-2 animate-in fade-in slide-in-from-top-1 duration-200">
                                                <div className="grid grid-cols-2 gap-3">
                                                    <div className="space-y-1">
                                                        <Label className="text-[10px] text-zinc-500 font-bold uppercase">Short Shifts</Label>
                                                        <Input
                                                            type="number"
                                                            className="h-11 text-xs"
                                                            min="0"
                                                            placeholder="e.g. 2"
                                                            value={shortShiftCount || ""}
                                                            onChange={(e) => setShortShiftCount(parseInt(e.target.value) || 0)}
                                                        />
                                                    </div>
                                                    <div className="space-y-1">
                                                        <Label className="text-[10px] text-zinc-500 font-bold uppercase">Hrs Worked</Label>
                                                        <Input
                                                            type="number"
                                                            className="h-11 text-xs"
                                                            min="0"
                                                            placeholder="e.g. 3"
                                                            value={totalWorkedInShortShifts || ""}
                                                            onChange={(e) => setTotalWorkedInShortShifts(parseFloat(e.target.value) || 0)}
                                                        />
                                                    </div>
                                                </div>
                                                <Button
                                                    variant="secondary"
                                                    size="sm"
                                                    className="w-full text-xs h-11 font-bold bg-[var(--primary)]/10 text-[var(--focus)] hover:bg-[var(--primary)]/20"
                                                    onClick={() => {
                                                        const shortfall = (shortShiftCount * 4) - totalWorkedInShortShifts;
                                                        if (shortfall > 0) {
                                                            setShortFallHours((prev) => (parseFloat(prev || "0") + shortfall).toString());
                                                            setShortShiftCount(0);
                                                            setTotalWorkedInShortShifts(0);
                                                            toast(`Added ${shortfall}h shortfall.`);
                                                        }
                                                    }}
                                                >
                                                    Calculate & Add
                                                </Button>
                                            </div>
                                        )}
                                    </div>
                                </div>
                            </div>
                        )}

                        {/* STEP 1 ΓÇö Sundays & Holidays */}
                        {currentStep === 1 && (
                            <div className="space-y-4">
                                <Alert variant="default">
                                    <AlertDescription>
                                        Sundays and Public Holidays are legally paid at{" "}
                                        <strong>2├ù the normal rate</strong> (BCEA).
                                    </AlertDescription>
                                </Alert>
                                <div className="space-y-2">
                                    <Label htmlFor="sunday">Sunday Hours ({employee.ordinarilyWorksSundays ? '1.5├ù rate' : '2├ù rate'})</Label>
                                    <Input
                                        id="sunday"
                                        type="number"
                                        min="0"
                                        placeholder="0"
                                        value={hours.sunday}
                                        onChange={(e) => setHours({ ...hours, sunday: e.target.value })}
                                    />
                                </div>
                                <div className="space-y-2">
                                    <Label htmlFor="holiday">Public Holiday Hours (2├ù rate)</Label>
                                    <Input
                                        id="holiday"
                                        type="number"
                                        min="0"
                                        placeholder={detectedHolidays.length > 0 ? `Suggested: ${detectedHolidays.length * 8}` : "0"}
                                        value={hours.holiday}
                                        onChange={(e) => setHours({ ...hours, holiday: e.target.value })}
                                    />
                                    {detectedHolidays.length > 0 && (
                                        <p className="text-[10px] font-medium animate-fade-in" style={{ color: "var(--primary)" }}>
                                            Found {detectedHolidays.length} holiday{detectedHolidays.length > 1 ? 's' : ''}: {detectedHolidays.map(h => h.name).join(", ")}.
                                        </p>
                                    )}
                                </div>
                            </div>
                        )}

                        {/* STEP 2 ΓÇö Deductions */}
                        {currentStep === 2 && (
                            <div className="space-y-4">
                                <Alert variant={totalHours > 24 ? "success" : "warning"}>
                                    <AlertDescription>
                                        <strong>UIF</strong> (1% employee + 1% employer) is{" "}
                                        <strong>{totalHours > 24 ? "applicable" : "NOT applicable"}</strong>{" "}
                                        ΓÇö worker has {totalHours > 24 ? "more than" : "24 or fewer"} hours per month.
                                    </AlertDescription>
                                </Alert>                                {leaveTrackingEnabled && (
                                    <div className="pt-4 space-y-4" style={{ borderTop: "1px solid var(--border)" }}>
                                        <h3 className="text-sm font-bold uppercase tracking-wider text-zinc-400 flex items-center gap-2">
                                            <AlertCircle className="w-4 h-4 text-[var(--focus)]" />
                                            Leave Taken (This Month)
                                        </h3>
                                        <div className="grid grid-cols-3 gap-3">
                                            <div className="space-y-1.5">
                                                <Label className="text-[10px] text-zinc-500 font-bold uppercase">Annual</Label>
                                                <Input
                                                    type="number"
                                                    className="h-11"
                                                    min="0"
                                                    placeholder="0"
                                                    value={leave.annual}
                                                    onChange={(e) => setLeave({ ...leave, annual: e.target.value })}
                                                />
                                            </div>
                                            <div className="space-y-1.5">
                                                <Label className="text-[10px] text-zinc-500 font-bold uppercase">Sick</Label>
                                                <Input
                                                    type="number"
                                                    className="h-11"
                                                    min="0"
                                                    placeholder="0"
                                                    value={leave.sick}
                                                    onChange={(e) => setLeave({ ...leave, sick: e.target.value })}
                                                />
                                            </div>
                                            <div className="space-y-1.5">
                                                <Label className="text-[10px] text-zinc-500 font-bold uppercase">Family</Label>
                                                <Input
                                                    type="number"
                                                    className="h-11"
                                                    min="0"
                                                    placeholder="0"
                                                    value={leave.family}
                                                    onChange={(e) => setLeave({ ...leave, family: e.target.value })}
                                                />
                                            </div>
                                        </div>
                                    </div>
                                )}
                                <button
                                    type="button"
                                    onClick={() => setIncludeAccommodation((v) => !v)}
                                    className={`w-full flex items-start gap-3 p-4 rounded-xl text-left transition-all duration-200 active:scale-[0.99] border-[1.5px] hover:bg-[var(--surface-2)] ${includeAccommodation ? "border-[var(--primary)] bg-[var(--primary)]/5" : "border-[var(--border)] bg-transparent"}`}
                                >
                                    <div
                                        className={`h-6 w-6 rounded flex items-center justify-center flex-shrink-0 mt-0.5 transition-all duration-200 border-[1.5px] ${includeAccommodation ? "bg-[var(--primary)] border-[var(--primary)]" : "bg-transparent border-[var(--border)]"}`}
                                    >
                                        {includeAccommodation && <Check className="h-3.5 w-3.5 text-white" strokeWidth={2.5} />}
                                    </div>
                                    <div>
                                        <p className="font-semibold text-sm" style={{ color: "var(--text)" }}>
                                            Accommodation Deduction
                                        </p>
                                        <p className="text-xs mt-0.5" style={{ color: "var(--text-muted)" }}>
                                            Deduct up to 10% of gross wage for accommodation provided (SD7 ΓÇö legal max).
                                        </p>
                                    </div>
                                </button>

                                {includeAccommodation && (
                                    <div className="space-y-2 px-1 animate-fade-in">
                                        <Label htmlFor="accommodationCost">Cost of Accommodation (Optional)</Label>
                                        <Input
                                            id="accommodationCost"
                                            type="number"
                                            min="0"
                                            placeholder="Automatically capped at 10% of gross"
                                            value={accommodationCost}
                                            onChange={(e) => setAccommodationCost(e.target.value)}
                                        />
                                    </div>
                                )}
                            </div>
                        )}

                        {/* STEP 3 ΓÇö Review */}
                        {currentStep === 3 && breakdown && (
                            <div className="space-y-4 animate-fade-in">
                                {employerDetailsGate && (
                                    <Alert variant="warning">
                                        <AlertDescription>
                                            Add your employer name and address before saving the first final payslip.
                                            {" "}
                                            <Link href="/settings" className="font-bold underline">
                                                Open Settings
                                            </Link>
                                        </AlertDescription>
                                    </Alert>
                                )}
                                {/* Duplicate payslip warning */}
                                {duplicateId && (
                                    <div className="p-4 rounded-xl border border-[var(--focus)]/40 bg-[var(--primary)]/5 space-y-3">
                                        <div className="flex items-center gap-2 text-sm font-bold" style={{ color: "var(--primary)" }}>
                                            <AlertTriangle className="h-4 w-4 shrink-0" />
                                            <span>A payslip for {employee.name} already exists for {format(safeDate(dates.start), "MMMM yyyy")}.</span>
                                        </div>
                                        <div className="flex gap-2">
                                            <Button
                                                size="sm"
                                                className="bg-[var(--primary)] text-white font-bold hover:brightness-95"
                                                onClick={async () => {
                                                    await deletePayslip(duplicateId);
                                                    setDuplicateId(null);
                                                    await doSave();
                                                }}
                                            >
                                                Replace existing
                                            </Button>
                                            <Button size="sm" variant="outline" onClick={() => setDuplicateId(null)}>Cancel</Button>
                                        </div>
                                    </div>
                                )}

                                {/* Compliance checklist */}
                                <div className="p-4 rounded-xl space-y-2.5" style={{ border: "1px solid var(--border)", backgroundColor: "var(--surface-2)" }}>
                                    <p className="text-[10px] font-black uppercase tracking-widest mb-3" style={{ color: "var(--text-muted)" }}>Compliance Check</p>
                                    <ComplianceRow
                                        pass={!!settings?.employerName?.trim() && !!settings?.employerAddress?.trim()}
                                        passText="Employer name and address set"
                                        failText="Employer details missing ΓÇö add them before you save the final payslip"
                                        failHref="/settings"
                                    />
                                    <ComplianceRow
                                        pass={employee.hourlyRate >= NMW_RATE}
                                        passText={`Rate meets NMW (R${NMW_RATE.toFixed(2)}/hr)`}
                                        failText={`Rate below NMW ΓÇö calculator auto-corrects to R${NMW_RATE.toFixed(2)}/hr`}
                                    />
                                    <ComplianceRow
                                        pass={totalHours > 24}
                                        passText="UIF deducted (1% employee + 1% employer)"
                                        failText="UIF not applicable ΓÇö worker has Γëñ24 hrs this period"
                                        isInfo={totalHours <= 24}
                                    />
                                    <ComplianceRow
                                        pass={Number(daysWorked) === 0 || (Number(hours.ordinary) / Math.max(Number(daysWorked), 1)) >= 4}
                                        passText="Hours meet 4-hr minimum shift rule"
                                        failText="Some shifts may be below 4 hrs ΓÇö calculator tops up automatically"
                                    />
                                </div>

                                {/* Earnings rows */}
                                <div
                                    className="rounded-xl overflow-hidden"
                                    style={{ border: "1px solid var(--border)" }}
                                >
                                    <div
                                        className="px-4 py-2.5 flex justify-between items-center text-xs font-bold uppercase tracking-widest"
                                        style={{
                                            backgroundColor: "var(--surface-2)",
                                            borderBottom: "1px solid var(--border)",
                                            color: "var(--text-muted)",
                                        }}
                                    >
                                        <span>Payslip Summary</span>
                                        <span>R{employee.hourlyRate.toFixed(2)}/hr</span>
                                    </div>

                                    {/* Earnings */}
                                    <div className="px-4 pt-4 pb-2 space-y-2">
                                        <p className="text-xs font-bold uppercase tracking-wider" style={{ color: "var(--primary)" }}>Earnings</p>
                                        <Row
                                            label={`Ordinary (${breakdown.effectiveOrdinaryHours}h${Number(shortFallHours) > 0 ? " inc. 4-hr minimum top-up" : ""})`}
                                            value={`R ${breakdown.ordinaryPay.toFixed(2)}`}
                                        />
                                        {(Number(hours.overtime) || 0) > 0 && <Row label={`Overtime (${Number(hours.overtime)}h)`} value={`R ${breakdown.overtimePay.toFixed(2)}`} />}
                                        {(Number(hours.sunday) || 0) > 0 && <Row label={`Sunday (${Number(hours.sunday)}h)`} value={`R ${breakdown.sundayPay.toFixed(2)}`} />}
                                        {(Number(hours.holiday) || 0) > 0 && <Row label={`Public Holiday (${Number(hours.holiday)}h)`} value={`R ${breakdown.publicHolidayPay.toFixed(2)}`} />}
                                        <Row label="Gross Pay" value={`R ${breakdown.grossPay.toFixed(2)}`} bold />
                                    </div>

                                    <div style={{ borderTop: "1px solid var(--border)" }} />

                                    {/* Deductions */}
                                    <div className="px-4 pt-3 pb-2 space-y-2">
                                        <p className="text-xs font-bold uppercase tracking-wider" style={{ color: "var(--primary)" }}>Deductions</p>
                                        <Row label={`UIF ${totalHours > 24 ? "(1%)" : "(n/a)"}`} value={`-R ${breakdown.deductions.uifEmployee.toFixed(2)}`} red />
                                        {includeAccommodation && breakdown.deductions.accommodation && (
                                            <Row label="Accommodation (10%)" value={`-R ${breakdown.deductions.accommodation.toFixed(2)}`} red />
                                        )}
                                        <Row label="Total Deductions" value={`R ${breakdown.deductions.total.toFixed(2)}`} bold />
                                    </div>

                                    {/* Net Pay bar */}
                                    <div
                                        className="flex justify-between items-center px-5 py-5"
                                        style={{ backgroundColor: "var(--primary)" }}
                                    >
                                        <span className="font-bold text-lg text-white">Net Pay</span>
                                        <span className="font-extrabold text-2xl text-white tabular-nums">
                                            R {breakdown.netPay.toFixed(2)}
                                        </span>
                                    </div>
                                </div>
                            </div>
                        )}
                    </CardContent>

                </Card>
            </main>

            <StickyBottomBar>
                <Button
                    size="lg"
                    variant="outline"
                    onClick={() => setCurrentStep((s) => Math.max(0, s - 1))}
                    disabled={currentStep === 0 || loading}
                >
                    Back
                </Button>
                <Button
                    size="lg"
                    onClick={handleNext}
                    disabled={loading}
                    className="flex-1 sm:flex-none sm:min-w-[160px] bg-[var(--primary)] hover:bg-[var(--primary-hover)] text-white font-bold"
                >
                    {loading ? (
                        <><Loader2 className="h-4 w-4 animate-spin" /> SavingΓÇª</>
                    ) : currentStep === STEPS.length - 1 ? (
                        "Save & Preview"
                    ) : (
                        <>Next <ArrowRight className="h-4 w-4" /></>
                    )}
                </Button>
            </StickyBottomBar>
        </div>
    );
}

function ComplianceRow({
    pass,
    passText,
    failText,
    failHref,
    isInfo,
}: {
    pass: boolean;
    passText: string;
    failText: string;
    failHref?: string;
    isInfo?: boolean;
}) {
    const color = pass ? "var(--success)" : isInfo ? "var(--blue-500)" : "var(--primary)";
    return (
        <div className="flex items-start gap-2.5 text-xs">
            {pass
                ? <CheckCircle2 className="h-4 w-4 shrink-0 mt-0.5" style={{ color: "var(--success)" }} />
                : <AlertTriangle className="h-4 w-4 shrink-0 mt-0.5" style={{ color }} />
            }
            <span style={{ color: pass ? "var(--text-muted)" : color }}>
                {pass ? passText : failText}
                {!pass && failHref && (
                    <Link href={failHref} className="ml-1 underline font-bold" style={{ color }}>Fix ΓåÆ</Link>
                )}
            </span>
        </div>
    );
}

function Row({
    label,
    value,
    bold,
    red,
}: {
    label: string;
    value: string;
    bold?: boolean;
    red?: boolean;
}) {
    return (
        <div className="flex justify-between items-center text-sm">
            <span className={bold ? "font-semibold text-[var(--text)]" : "text-[var(--text-muted)]"}>
                {label}
            </span>
            <span
                className={`tabular-nums ${red ? "text-[var(--danger)]" : bold ? "text-[var(--text)] font-bold" : "text-[var(--text-muted)]"}`}
            >
                {value}
            </span>
        </div>
    );
}

export default function WizardPage() {
    return (
        <React.Suspense
            fallback={
                <div className="min-h-screen flex items-center justify-center" style={{ backgroundColor: "var(--bg)" }}>
                    <Loader2 className="h-8 w-8 animate-spin" style={{ color: "var(--primary)" }} />
                </div>
            }
        >
            <WizardContent />
        </React.Suspense>
    );
}

"use client";

import * as React from "react";
import { ArrowLeft, ArrowRight, Save, Loader2, FileText, Clock, Banknote, Calendar, Home, ShieldAlert, CheckCircle2, BriefcaseBusiness, FileSignature } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import { Contract, Employee, EmployerSettings } from "@/lib/schema";
import { CONTRACT_TEMPLATE_META } from "@/src/config/contract-template";

export const WIZARD_STEPS = [
    { label: "Employee", description: "Choose the worker" },
    { label: "Parties", description: "Job and workplace" },
    { label: "Hours", description: "Schedule" },
    { label: "Pay", description: "Pay and leave" },
    { label: "Terms", description: "Key clauses" },
    { label: "Review", description: "Final check" },
];

function textList(value: string) {
    return value
        .split("\n")
        .map((item) => item.trim())
        .filter(Boolean);
}

export interface ContractFormWizardProps {
    currentStep: number;
    setCurrentStep: React.Dispatch<React.SetStateAction<number>>;
    formData: Partial<Contract>;
    setFormData: React.Dispatch<React.SetStateAction<Partial<Contract>>>;
    employees: Employee[];
    settings: EmployerSettings;
    saving: boolean;
    onSave: () => void;
    onBackToTop: () => void;
}

const STORAGE_KEY = "lekkerledger-contract-draft-state";

export function ContractFormWizard({
    currentStep,
    setCurrentStep,
    formData,
    setFormData,
    employees,
    settings,
    saving,
    onSave,
    onBackToTop,
}: ContractFormWizardProps) {
    const selectedEmployee = employees.find((employee) => employee.id === formData.employeeId);
    const initialDuties = formData.duties?.join("\n") || "General cleaning\nLaundry\nBasic household support";
    const [dutiesInput, setDutiesInput] = React.useState(initialDuties);

    // Save to session storage on change to preserve state if navigating away
    React.useEffect(() => {
        try {
            sessionStorage.setItem(STORAGE_KEY, JSON.stringify({ currentStep, formData }));
        } catch (error) {
            console.error("Failed to save wizard state to session storage", error);
        }
    }, [currentStep, formData]);

    // Calculate hourly rate for NMW check
    const isMonthly = formData.salary?.frequency === "Monthly";
    const isFortnightly = formData.salary?.frequency === "Fortnightly";
    const weeksPerYear = 52.14;
    const monthsPerYear = 12;

    let hourlyRate = 0;
    if (formData.salary?.amount && formData.workingHours?.daysPerWeek && formData.workingHours?.startAt && formData.workingHours?.endAt) {
        const start = formData.workingHours.startAt.split(":").map(Number);
        const end = formData.workingHours.endAt.split(":").map(Number);
        let hoursPerDay = (end[0] + end[1] / 60) - (start[0] + start[1] / 60);

        // Subtract break duration in hours
        if (formData.workingHours.breakDuration) {
            hoursPerDay -= formData.workingHours.breakDuration / 60;
        }

        const weeklyHours = hoursPerDay * formData.workingHours.daysPerWeek;

        if (weeklyHours > 0) {
            if (isMonthly) {
                const weeklyPay = (formData.salary.amount * monthsPerYear) / weeksPerYear;
                hourlyRate = weeklyPay / weeklyHours;
            } else if (isFortnightly) {
                const weeklyPay = formData.salary.amount / 2;
                hourlyRate = weeklyPay / weeklyHours;
            } else {
                // Weekly
                hourlyRate = formData.salary.amount / weeklyHours;
            }
        }
    }

    const handleNext = () => setCurrentStep((step) => Math.min(step + 1, WIZARD_STEPS.length - 1));
    const handleBack = () => setCurrentStep((step) => Math.max(step - 1, 0));

    return (
        <Card className="glass-panel border-none shadow-2xl overflow-hidden">
            <CardContent className="p-0">
                {currentStep === 0 && (
                    <div className="p-8 space-y-6">
                        <div className="flex items-center gap-4">
                            <div className="h-12 w-12 rounded-2xl bg-[var(--primary)] flex items-center justify-center">
                                <FileText className="h-6 w-6 text-white" />
                            </div>
                            <div>
                                <h3 className="text-lg font-black text-[var(--text)]">Choose the employee</h3>
                                <p className="text-sm text-[var(--text-muted)]">This contract will use the employeeΓÇÖs saved details as the starting point.</p>
                            </div>
                        </div>
                        <div className="grid grid-cols-1 gap-3">
                            {employees.map((employee) => (
                                <button
                                    key={employee.id}
                                    onClick={() => setFormData((current) => ({ ...current, employeeId: employee.id }))}
                                    className={`flex items-center justify-between rounded-2xl border p-4 text-left transition-all ${formData.employeeId === employee.id ? "border-[var(--primary)] bg-[var(--primary)]/6" : "border-[var(--border)] hover:border-[var(--primary)]/25"}`}
                                >
                                    <div>
                                        <p className="font-bold text-[var(--text)]">{employee.name}</p>
                                        <p className="text-xs text-[var(--text-muted)]">{employee.role}</p>
                                    </div>
                                    {formData.employeeId === employee.id && <CheckCircle2 className="h-5 w-5 text-[var(--primary)]" />}
                                </button>
                            ))}
                        </div>
                        <Alert>
                            <FileSignature className="h-4 w-4" />
                            <AlertDescription>
                                Start with the employee you already saved. You will still be able to adjust the job terms, hours, pay, leave, and wording before the draft is saved.
                            </AlertDescription>
                        </Alert>
                    </div>
                )}

                {currentStep === 1 && (
                    <div className="p-8 space-y-6">
                        <div className="grid gap-4 md:grid-cols-2">
                            <Field label="Job title">
                                <input
                                    type="text"
                                    value={formData.jobTitle}
                                    onChange={(event) => setFormData((current) => ({ ...current, jobTitle: event.target.value }))}
                                    className="w-full h-11 px-4 rounded-xl border border-[var(--border)] bg-[var(--surface-1)]"
                                />
                            </Field>
                            <Field label="Effective date">
                                <input
                                    type="date"
                                    value={formData.effectiveDate}
                                    onChange={(event) => setFormData((current) => ({ ...current, effectiveDate: event.target.value }))}
                                    className="w-full h-11 px-4 rounded-xl border border-[var(--border)] bg-[var(--surface-1)]"
                                />
                            </Field>
                        </div>
                        <Field label="Employee address">
                            <input
                                type="text"
                                value={formData.employeeAddress || selectedEmployee?.address || ""}
                                onChange={(event) => setFormData((current) => ({ ...current, employeeAddress: event.target.value }))}
                                className="w-full h-11 px-4 rounded-xl border border-[var(--border)] bg-[var(--surface-1)]"
                                placeholder="Employee residential address"
                            />
                        </Field>
                        <Field label="Place of work">
                            <input
                                type="text"
                                value={formData.placeOfWork || ""}
                                onChange={(event) => setFormData((current) => ({ ...current, placeOfWork: event.target.value }))}
                                className="w-full h-11 px-4 rounded-xl border border-[var(--border)] bg-[var(--surface-1)]"
                                placeholder="Household address or main work location"
                            />
                        </Field>
                        <Field label="Main duties">
                            <textarea
                                value={dutiesInput}
                                onChange={(event) => {
                                    setDutiesInput(event.target.value);
                                    setFormData((current) => ({ ...current, duties: textList(event.target.value) }));
                                }}
                                className="min-h-[160px] w-full rounded-2xl border border-[var(--border)] bg-[var(--surface-1)] p-4"
                                placeholder={"General cleaning\nLaundry\nChildcare support\nMeal preparation"}
                            />
                        </Field>
                        <Alert>
                            <BriefcaseBusiness className="h-4 w-4" />
                            <AlertDescription>
                                Keep this practical and specific. It is better to describe the real household duties than to leave them vague.
                            </AlertDescription>
                        </Alert>
                    </div>
                )}

                {currentStep === 2 && (
                    <div className="p-8 space-y-6">
                        <div className="grid gap-4 md:grid-cols-2">
                            <Field label="Days per week">
                                <input
                                    type="number"
                                    value={formData.workingHours?.daysPerWeek}
                                    onChange={(event) => setFormData((current) => ({ ...current, workingHours: { ...current.workingHours!, daysPerWeek: parseInt(event.target.value, 10) || 0 } }))}
                                    className="w-full h-11 px-4 rounded-xl border border-[var(--border)] bg-[var(--surface-1)]"
                                />
                            </Field>
                            <Field label="Break (minutes)">
                                <input
                                    type="number"
                                    value={formData.workingHours?.breakDuration}
                                    onChange={(event) => setFormData((current) => ({ ...current, workingHours: { ...current.workingHours!, breakDuration: parseInt(event.target.value, 10) || 0 } }))}
                                    className="w-full h-11 px-4 rounded-xl border border-[var(--border)] bg-[var(--surface-1)]"
                                />
                            </Field>
                        </div>
                        <div className="grid gap-4 md:grid-cols-2">
                            <Field label="Work starts">
                                <input
                                    type="time"
                                    value={formData.workingHours?.startAt}
                                    onChange={(event) => setFormData((current) => ({ ...current, workingHours: { ...current.workingHours!, startAt: event.target.value } }))}
                                    className="w-full h-11 px-4 rounded-xl border border-[var(--border)] bg-[var(--surface-1)]"
                                />
                            </Field>
                            <Field label="Work ends">
                                <input
                                    type="time"
                                    value={formData.workingHours?.endAt}
                                    onChange={(event) => setFormData((current) => ({ ...current, workingHours: { ...current.workingHours!, endAt: event.target.value } }))}
                                    className="w-full h-11 px-4 rounded-xl border border-[var(--border)] bg-[var(--surface-1)]"
                                />
                            </Field>
                        </div>
                    </div>
                )}

                {currentStep === 3 && (
                    <div className="p-8 space-y-6">
                        <div className="grid gap-4 md:grid-cols-2">
                            <Field label="Pay amount (R)">
                                <input
                                    type="number"
                                    value={formData.salary?.amount}
                                    onChange={(event) => setFormData((current) => ({ ...current, salary: { ...current.salary!, amount: parseFloat(event.target.value) || 0 } }))}
                                    className="w-full h-11 px-4 rounded-xl border border-[var(--border)] bg-[var(--surface-1)]"
                                />
                            </Field>
                            <Field label="Pay frequency">
                                <select
                                    value={formData.salary?.frequency}
                                    onChange={(event) => setFormData((current) => ({ ...current, salary: { ...current.salary!, frequency: event.target.value as Contract["salary"]["frequency"] } }))}
                                    className="w-full h-11 px-4 rounded-xl border border-[var(--border)] bg-[var(--surface-1)]"
                                >
                                    <option value="Monthly">Monthly</option>
                                    <option value="Fortnightly">Fortnightly</option>
                                    <option value="Weekly">Weekly</option>
                                </select>
                            </Field>
                        </div>

                        {hourlyRate > 0 && hourlyRate < 30.23 && (
                            <Alert variant="warning">
                                <AlertTitle>NMW Warning</AlertTitle>
                                <AlertDescription>
                                    The effective hourly rate based on these hours and pay is <strong>R{hourlyRate.toFixed(2)}/hr</strong>. The National Minimum Wage for 2026 is <strong>R30.23/hr</strong>. Please ensure you are compliant.
                                </AlertDescription>
                            </Alert>
                        )}

                        <div className="grid gap-4 md:grid-cols-2">
                            <Field label="Annual leave days">
                                <input
                                    type="number"
                                    value={formData.leave?.annualDays}
                                    onChange={(event) => setFormData((current) => ({ ...current, leave: { ...current.leave!, annualDays: parseInt(event.target.value, 10) || 0 } }))}
                                    className="w-full h-11 px-4 rounded-xl border border-[var(--border)] bg-[var(--surface-1)]"
                                />
                            </Field>
                            <Field label="Sick leave days">
                                <input
                                    type="number"
                                    value={formData.leave?.sickDays}
                                    onChange={(event) => setFormData((current) => ({ ...current, leave: { ...current.leave!, sickDays: parseInt(event.target.value, 10) || 0 } }))}
                                    className="w-full h-11 px-4 rounded-xl border border-[var(--border)] bg-[var(--surface-1)]"
                                />
                                <p className="text-[10px] text-[var(--text-muted)] mt-1">
                                    Usually 1 day per 26 days worked for the first 6 months, then 30 days over a 3-year cycle.
                                </p>
                            </Field>
                        </div>
                        <Alert>
                            <Banknote className="h-4 w-4" />
                            <AlertDescription>
                                Use the actual agreed pay arrangement here. If overtime, Sundays, public holidays, or accommodation need special wording, cover that in the next step.
                            </AlertDescription>
                        </Alert>
                    </div>
                )}

                {currentStep === 4 && (
                    <div className="p-8 space-y-6">
                        <div className="grid gap-4 md:grid-cols-2">
                            <Field label="Accommodation provided?">
                                <label className="flex items-center gap-3 rounded-2xl border border-[var(--border)] bg-[var(--surface-1)] px-4 py-3 cursor-pointer select-none">
                                    <input
                                        type="checkbox"
                                        checked={formData.terms?.accommodationProvided}
                                        onChange={(event) => setFormData((current) => ({ ...current, terms: { ...current.terms!, accommodationProvided: event.target.checked } }))}
                                        className="h-4 w-4"
                                    />
                                    <span className="text-sm text-[var(--text)]">Yes, accommodation is part of this job</span>
                                </label>
                            </Field>
                            <Field label="Accommodation details">
                                <input
                                    type="text"
                                    value={formData.terms?.accommodationDetails}
                                    onChange={(event) => setFormData((current) => ({ ...current, terms: { ...current.terms!, accommodationDetails: event.target.value } }))}
                                    className="w-full h-11 px-4 rounded-xl border border-[var(--border)] bg-[var(--surface-1)] disabled:opacity-50"
                                    placeholder="Room details, utilities, deduction notes, or other accommodation terms"
                                    disabled={!formData.terms?.accommodationProvided}
                                />
                            </Field>
                        </div>
                        {formData.terms?.accommodationProvided && (
                            <Alert variant="warning">
                                <AlertTitle>Deduction Limit</AlertTitle>
                                <AlertDescription>
                                    Under Sectoral Determination 7, any accommodation deduction is capped at <strong>10%</strong> of the employee&apos;s wage.
                                </AlertDescription>
                            </Alert>
                        )}
                        <Field label="Overtime wording">
                            <textarea
                                value={formData.terms?.overtimeAgreement}
                                onChange={(event) => setFormData((current) => ({ ...current, terms: { ...current.terms!, overtimeAgreement: event.target.value } }))}
                                className="min-h-[100px] w-full rounded-2xl border border-[var(--border)] bg-[var(--surface-1)] p-4"
                            />
                        </Field>
                        <Field label="Sunday / public holiday wording">
                            <textarea
                                value={formData.terms?.sundayHolidayAgreement}
                                onChange={(event) => setFormData((current) => ({ ...current, terms: { ...current.terms!, sundayHolidayAgreement: event.target.value } }))}
                                className="min-h-[100px] w-full rounded-2xl border border-[var(--border)] bg-[var(--surface-1)] p-4"
                            />
                        </Field>
                        <Field label="Notice wording">
                            <textarea
                                value={formData.terms?.noticeClause}
                                onChange={(event) => setFormData((current) => ({ ...current, terms: { ...current.terms!, noticeClause: event.target.value } }))}
                                className="min-h-[100px] w-full rounded-2xl border border-[var(--border)] bg-[var(--surface-1)] p-4"
                            />
                        </Field>
                        <Alert>
                            <ShieldAlert className="h-4 w-4" />
                            <AlertDescription>
                                This draft follows the labour sample structure, but it is still not legal advice. Make sure the wording matches the real arrangement before anyone signs.
                            </AlertDescription>
                        </Alert>
                        <label className="flex items-start gap-3 rounded-2xl border border-[var(--primary)]/30 bg-[var(--primary)]/5 p-4 cursor-pointer">
                            <input
                                type="checkbox"
                                checked={formData.terms?.lawyerReviewAcknowledged}
                                onChange={(event) => setFormData((current) => ({ ...current, terms: { ...current.terms!, lawyerReviewAcknowledged: event.target.checked } }))}
                                className="mt-1 h-4 w-4"
                            />
                            <div>
                                <p className="text-sm font-bold text-[var(--text)]">I understand this draft must be verified</p>
                                <p className="text-xs text-[var(--text-muted)] mt-1">
                                    The next step saves the contract draft into Documents. Review the generated PDF carefully, then only sign a version you are comfortable with and keep that signed version with the employeeΓÇÖs records. If you can, have a South African labour lawyer review the final wording.
                                </p>
                            </div>
                        </label>
                    </div>
                )}

                {currentStep === 5 && (
                    <div className="p-8 space-y-6">
                        <div className="rounded-2xl border border-[var(--border)] bg-[var(--surface-2)]/55 p-6 space-y-5">
                            <h3 className="text-lg font-black text-[var(--text)]">Draft summary</h3>
                            <div className="grid gap-4 md:grid-cols-2">
                                <SummaryRow icon={FileText} label="Employee" value={selectedEmployee?.name ?? "Not selected"} />
                                <SummaryRow icon={Calendar} label="Effective date" value={formData.effectiveDate ?? ""} />
                                <SummaryRow icon={Home} label="Place of work" value={formData.placeOfWork || "Not set"} />
                                <SummaryRow icon={Banknote} label="Pay" value={`R${formData.salary?.amount?.toFixed(2) ?? "0.00"} (${formData.salary?.frequency})`} />
                                <SummaryRow icon={Clock} label="Schedule" value={`${formData.workingHours?.daysPerWeek} days/week, ${formData.workingHours?.startAt} to ${formData.workingHours?.endAt}`} />
                                <SummaryRow icon={CheckCircle2} label="Lawyer review reminder" value={formData.terms?.lawyerReviewAcknowledged ? "Acknowledged" : "Still needs acknowledgement"} />
                            </div>
                            <div className="rounded-2xl border border-[var(--border)] bg-[var(--surface-1)] p-4 space-y-2">
                                <p className="text-[10px] font-black uppercase tracking-widest text-[var(--text-muted)]">What happens next</p>
                                <p className="text-sm text-[var(--text)]">
                                    Generating creates a draft contract in Documents. From there, you can preview the PDF, download it, talk through the wording with the employee, and only sign the final version you are happy with.
                                </p>
                                <p className="text-xs text-[var(--text-muted)]">
                                    Template version {CONTRACT_TEMPLATE_META.versionLabel} ┬╖ Last updated {CONTRACT_TEMPLATE_META.updatedAtLabel}
                                </p>
                            </div>

                            {!formData.terms?.lawyerReviewAcknowledged && (
                                <Alert variant="warning">
                                    <AlertTitle>One step remaining before you can generate</AlertTitle>
                                    <AlertDescription>
                                        <p className="mb-3">You haven&apos;t confirmed the review reminder on the Terms step. Go back and tick the acknowledgement ΓÇö it only takes a second.</p>
                                        <Button variant="outline" size="sm" onClick={() => setCurrentStep(4)}>
                                            ΓåÉ Back to Terms
                                        </Button>
                                    </AlertDescription>
                                </Alert>
                            )}
                        </div>
                    </div>
                )}

                <div className="flex items-center justify-between border-t border-[var(--border)] bg-[var(--surface-2)]/45 p-6">
                    <Button variant="ghost" onClick={currentStep === 0 ? onBackToTop : handleBack} disabled={saving}>{currentStep === 0 ? "Back" : "Previous"}</Button>
                    {currentStep === WIZARD_STEPS.length - 1 ? (
                        <Button
                            onClick={onSave}
                            disabled={saving || !formData.terms?.lawyerReviewAcknowledged}
                            className="bg-[var(--primary)] text-white hover:bg-[var(--primary-hover)] gap-2"
                        >
                            {saving ? <Loader2 className="h-4 w-4 animate-spin" /> : <Save className="h-4 w-4" />}
                            {saving ? "Generating..." : "Generate draft"}
                        </Button>
                    ) : (
                        <Button onClick={handleNext} className="bg-[var(--primary)] text-white hover:bg-[var(--primary-hover)] gap-2">
                            Next <ArrowRight className="h-4 w-4" />
                        </Button>
                    )}
                </div>
            </CardContent>
        </Card>
    );
}

function Field({ label, children }: { label: string; children: React.ReactNode }) {
    return (
        <div className="space-y-1.5">
            <label className="text-[10px] font-black uppercase tracking-widest text-[var(--text-muted)]">{label}</label>
            {children}
        </div>
    );
}

function SummaryRow({ icon: Icon, label, value }: { icon: React.ElementType; label: string; value: string }) {
    return (
        <div className="flex items-start gap-3">
            <div className="mt-0.5 flex h-9 w-9 items-center justify-center rounded-xl bg-[var(--surface-1)] text-[var(--primary)]">
                <Icon className="h-4 w-4" />
            </div>
            <div>
                <p className="text-[10px] font-black uppercase tracking-widest text-[var(--text-muted)]">{label}</p>
                <p className="text-sm font-semibold text-[var(--text)]">{value}</p>
            </div>
        </div>
    );
}

import { format } from "date-fns";
import { PDFDocument, type PDFFont, type PDFPage } from "pdf-lib";
import { buildContractClauses } from "./contractTemplate";
import type { Contract, Employee, EmployerSettings } from "../schema";
import { getNMWRecordForDate } from "../legal/registry";
import { loadPdfFonts } from "../pdf-fonts";
import { drawPdfBrandLockup } from "../pdf-brand";
import { PDF_COLORS, PDF_LAYOUT } from "../pdf-theme";
import { CONTRACT_TEMPLATE_META } from "@/src/config/contract-template";

type ResolvedContractDraft = {
    contract: Contract;
    employee: Employee;
    settings: EmployerSettings;
};

const PAGE_W = 595.28;
const PAGE_H = 841.89;
const MARGIN = PDF_LAYOUT.MARGIN;
const BODY_W = PAGE_W - MARGIN * 2;

function isContract(value: Contract | Employee): value is Contract {
    return "employeeId" in value;
}

function createLegacyContract(employee: Employee, settings: EmployerSettings): Contract {
    return {
        id: crypto.randomUUID(),
        householdId: employee.householdId ?? "default",
        employeeId: employee.id,
        status: "draft",
        version: 1,
        effectiveDate: employee.startDate || new Date().toISOString().split("T")[0],
        jobTitle: employee.role || "Domestic worker",
        placeOfWork: settings.employerAddress || "",
        duties: ["General cleaning", "Laundry", "Basic household support"],
        workingHours: {
            daysPerWeek: 5,
            startAt: "08:00",
            endAt: "17:00",
            breakDuration: 60,
        },
        salary: {
            amount: Number((employee.hourlyRate * 195).toFixed(2)),
            frequency: employee.frequency || "Monthly",
        },
        leave: {
            annualDays: 21,
            sickDays: 30,
        },
        terms: {
            accommodationProvided: false,
            accommodationDetails: "",
            overtimeAgreement: "Any overtime must be agreed in advance and paid according to the BCEA.",
            sundayHolidayAgreement: employee.ordinarilyWorksSundays
                ? "Sunday work forms part of the normal schedule and must still be paid at the correct statutory rate."
                : "Sunday or public-holiday work must be agreed in advance and paid at the correct statutory rate.",
            noticeClause: "Notice periods must follow the BCEA and must be given in writing.",
            lawyerReviewAcknowledged: false,
        },
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
    };
}

function resolveDraft(
    contractOrEmployee: Contract | Employee,
    employeeOrSettings: Employee | EmployerSettings,
    maybeSettings?: EmployerSettings,
): ResolvedContractDraft {
    if (isContract(contractOrEmployee)) {
        return {
            contract: contractOrEmployee,
            employee: employeeOrSettings as Employee,
            settings: maybeSettings as EmployerSettings,
        };
    }

    const employee = contractOrEmployee;
    const settings = employeeOrSettings as EmployerSettings;
    return {
        contract: createLegacyContract(employee, settings),
        employee,
        settings,
    };
}

function addPage(pdfDoc: PDFDocument, fonts: PdfFonts) {
    const page = pdfDoc.addPage([PAGE_W, PAGE_H]);
    page.drawRectangle({ x: 0, y: 0, width: PAGE_W, height: PAGE_H, color: PDF_COLORS.PAPER });
    drawPdfBrandLockup(page, {
        x: MARGIN,
        y: PAGE_H - 60,
        size: 24,
        serifBold: fonts.serifBold,
        sansBold: fonts.sansBold,
        subtitle: "HOUSEHOLD EMPLOYMENT RECORD",
    });
    page.drawLine({
        start: { x: MARGIN, y: PAGE_H - 90 },
        end: { x: PAGE_W - MARGIN, y: PAGE_H - 90 },
        thickness: 1,
        color: PDF_COLORS.BORDER,
    });
    const footerText = `Prepared using LekkerLedger ┬╖ Based on the DEL domestic-worker sample structure ┬╖ Review carefully before signing and keep the signed copy with the employee's records.`;
    page.drawLine({
        start: { x: MARGIN, y: 38 },
        end: { x: PAGE_W - MARGIN, y: 38 },
        thickness: 0.5,
        color: PDF_COLORS.BORDER,
    });
    page.drawText(footerText, {
        x: PAGE_W / 2 - fonts.sansRegular.widthOfTextAtSize(footerText, 8) / 2,
        y: 25,
        size: 8,
        font: fonts.sansRegular,
        color: PDF_COLORS.TEXT_MUTED,
    });
    return page;
}

type PdfFonts = {
    sansRegular: PDFFont;
    sansBold: PDFFont;
    serifBold: PDFFont;
};

function ensureSpace(
    pdfDoc: PDFDocument,
    fonts: PdfFonts,
    currentPage: PDFPage,
    cy: number,
    requiredSpace: number
): { page: PDFPage; cy: number } {
    const MIN_Y = MARGIN + 60; // bottom margin + footer clearance
    if (cy - requiredSpace < MIN_Y) {
        const newPage = addPage(pdfDoc, fonts);
        return { page: newPage, cy: PAGE_H - 120 };
    }
    return { page: currentPage, cy };
}

function drawSection(page: PDFPage, fonts: PdfFonts, title: string, y: number) {
    page.drawText(title, {
        x: MARGIN,
        y,
        size: 10,
        font: fonts.sansBold,
        color: PDF_COLORS.TEXT,
    });
    page.drawLine({
        start: { x: MARGIN, y: y - 8 },
        end: { x: PAGE_W - MARGIN, y: y - 8 },
        thickness: 0.5,
        color: PDF_COLORS.BORDER,
    });
}

function drawRow(page: PDFPage, fonts: PdfFonts, label: string, value: string, y: number) {
    page.drawText(`${label}:`, {
        x: MARGIN + 8,
        y,
        size: 10,
        font: fonts.sansBold,
        color: PDF_COLORS.TEXT_MUTED,
    });
    page.drawText(value || "ΓÇö", {
        x: MARGIN + 210,
        y,
        size: 10,
        font: fonts.sansRegular,
        color: PDF_COLORS.TEXT,
        maxWidth: BODY_W - 220,
    });
    page.drawLine({
        start: { x: MARGIN, y: y - 5 },
        end: { x: PAGE_W - MARGIN, y: y - 5 },
        thickness: 0.2,
        color: PDF_COLORS.RULING_LINE,
    });
}

function drawParagraph(page: PDFPage, fonts: PdfFonts, text: string, y: number, maxWidth = BODY_W - 16) {
    const lines = Math.max(1, Math.ceil(fonts.sansRegular.widthOfTextAtSize(text, 10) / maxWidth));
    page.drawText(text, {
        x: MARGIN + 8,
        y,
        size: 10,
        font: fonts.sansRegular,
        color: PDF_COLORS.TEXT,
        maxWidth,
        lineHeight: 14,
    });
    return y - (lines * 14 + 10);
}

function drawBulletList(page: PDFPage, fonts: PdfFonts, items: string[], y: number, maxWidth = BODY_W - 28) {
    let currentY = y;
    items.forEach((item) => {
        page.drawText("ΓÇó", {
            x: MARGIN + 8,
            y: currentY,
            size: 10,
            font: fonts.sansBold,
            color: PDF_COLORS.PRIMARY_GREEN,
        });
        const lines = Math.max(1, Math.ceil(fonts.sansRegular.widthOfTextAtSize(item, 10) / maxWidth));
        page.drawText(item, {
            x: MARGIN + 22,
            y: currentY,
            size: 10,
            font: fonts.sansRegular,
            color: PDF_COLORS.TEXT,
            maxWidth,
            lineHeight: 14,
        });
        currentY -= (lines * 14 + 6);
    });
    return currentY;
}

export async function generateEmploymentContract(
    contractOrEmployee: Contract | Employee,
    employeeOrSettings: Employee | EmployerSettings,
    maybeSettings?: EmployerSettings,
): Promise<Uint8Array> {
    const { contract, employee, settings } = resolveDraft(contractOrEmployee, employeeOrSettings, maybeSettings);
    const pdfDoc = await PDFDocument.create();
    const fonts: PdfFonts = await loadPdfFonts(pdfDoc);

    const startDate = contract.effectiveDate ? new Date(contract.effectiveDate) : new Date();
    const effectiveDate = format(startDate, "d MMMM yyyy");
    const todayStr = format(new Date(), "d MMMM yyyy");
    const nmwRecord = getNMWRecordForDate(startDate);
    const nmwDateStr = format(new Date(nmwRecord.effectiveDate), "d MMMM yyyy");
    const hours = contract.workingHours;
    const duties = contract.duties.length > 0 ? contract.duties : ["General household duties agreed by the employer and employee."];

    const pageOne = addPage(pdfDoc, fonts);
    pageOne.drawText("Employment Contract", {
        x: MARGIN,
        y: PAGE_H - 60,
        size: 18,
        font: fonts.serifBold,
        color: PDF_COLORS.TEXT,
    });
    const subtitle = `Prepared using LekkerLedger ┬╖ Based on the DEL domestic-worker sample structure ┬╖ Review before signing`;
    pageOne.drawText(subtitle, {
        x: MARGIN,
        y: PAGE_H - 76,
        size: 8,
        font: fonts.sansRegular,
        color: PDF_COLORS.TEXT_MUTED,
        maxWidth: BODY_W,
    });
    pageOne.drawText(`Effective date: ${effectiveDate}   | Draft prepared: ${todayStr}`, {
        x: MARGIN,
        y: PAGE_H - 110,
        size: 8,
        font: fonts.sansRegular,
        color: PDF_COLORS.TEXT_MUTED,
    });
    pageOne.drawText(`Template version ${CONTRACT_TEMPLATE_META.versionLabel}   | Last updated ${CONTRACT_TEMPLATE_META.updatedAtLabel}`, {
        x: MARGIN,
        y: PAGE_H - 122,
        size: 8,
        font: fonts.sansRegular,
        color: PDF_COLORS.TEXT_MUTED,
    });

    let cy = PAGE_H - 148;
    let currentPage = pageOne;

    const clauses = buildContractClauses(contract, employee, settings);

    for (let i = 0; i < clauses.length; i++) {
        const clause = clauses[i];

        ({ page: currentPage, cy } = ensureSpace(pdfDoc, fonts, currentPage, cy, 80));

        if (clause.type === "signatures") {
            ({ page: currentPage, cy } = ensureSpace(pdfDoc, fonts, currentPage, cy, 180));
            drawSection(currentPage, fonts, `${i + 1}. ${clause.title}`, cy);
            cy -= 48;
            currentPage.drawLine({
                start: { x: MARGIN, y: cy },
                end: { x: MARGIN + 190, y: cy },
                thickness: 0.5,
                color: PDF_COLORS.TEXT,
            });
            currentPage.drawText("Employer signature", {
                x: MARGIN,
                y: cy - 14,
                size: 8,
                font: fonts.sansBold,
                color: PDF_COLORS.TEXT_MUTED,
            });
            currentPage.drawText(settings.employerName || "Employer", {
                x: MARGIN,
                y: cy - 26,
                size: 8,
                font: fonts.sansRegular,
                color: PDF_COLORS.TEXT,
            });
            currentPage.drawText("Date: ____________________", {
                x: MARGIN,
                y: cy - 40,
                size: 8,
                font: fonts.sansRegular,
                color: PDF_COLORS.TEXT_MUTED,
            });

            const rightX = PAGE_W - MARGIN - 190;
            currentPage.drawLine({
                start: { x: rightX, y: cy },
                end: { x: rightX + 190, y: cy },
                thickness: 0.5,
                color: PDF_COLORS.TEXT,
            });
            currentPage.drawText("Employee signature", {
                x: rightX,
                y: cy - 14,
                size: 8,
                font: fonts.sansBold,
                color: PDF_COLORS.TEXT_MUTED,
            });
            currentPage.drawText(employee.name, {
                x: rightX,
                y: cy - 26,
                size: 8,
                font: fonts.sansRegular,
                color: PDF_COLORS.TEXT,
            });
            currentPage.drawText("Date: ____________________", {
                x: rightX,
                y: cy - 40,
                size: 8,
                font: fonts.sansRegular,
                color: PDF_COLORS.TEXT_MUTED,
            });
            continue;
        }

        drawSection(currentPage, fonts, `${i + 1}. ${clause.title}`, cy);
        cy -= 26;

        if (clause.type === "rows" && clause.rows) {
            for (const row of clause.rows) {
                ({ page: currentPage, cy } = ensureSpace(pdfDoc, fonts, currentPage, cy, 24));
                drawRow(currentPage, fonts, row.label, row.value, cy);
                cy -= 18;
            }
            cy -= 8;
        } else if (clause.type === "paragraphs" && clause.paragraphs) {
            for (const p of clause.paragraphs) {
                ({ page: currentPage, cy } = ensureSpace(pdfDoc, fonts, currentPage, cy, 40));
                cy = drawParagraph(currentPage, fonts, p, cy);
            }
            cy -= 6;
        } else if (clause.type === "bullets" && clause.bullets) {
            ({ page: currentPage, cy } = ensureSpace(pdfDoc, fonts, currentPage, cy, 40));
            cy = drawBulletList(currentPage, fonts, clause.bullets, cy);
            cy -= 10;
        }
    }

    return pdfDoc.save();
}

export function buildContractFileName(contract: Contract, employee: Employee) {
    const safeName = employee.name.trim().replace(/\s+/g, "_");
    return `Contract_${safeName}_v${contract.version}.pdf`;
}

import { PLANS, PlanId, PlanConfig } from "../config/plans";
